        column.Width = width;
        column.AutoSizeMode = DataGridViewAutoSizeColumnMode.None;
    }

    private WorkflowGuideStep? GetSelectedWorkflowStep()
    {
        if (_workflowGuideGrid.SelectedRows.Count > 0 && _workflowGuideGrid.SelectedRows[0].DataBoundItem is WorkflowGuideStep selected) return selected;
        if (_workflowGuideGrid.CurrentRow?.DataBoundItem is WorkflowGuideStep current) return current;
        return null;
    }

    private WorkflowActionItem? GetSelectedWorkflowActionItem()
    {
        if (_workflowActionGrid.SelectedRows.Count > 0 && _workflowActionGrid.SelectedRows[0].DataBoundItem is WorkflowActionItem selected) return selected;
        if (_workflowActionGrid.CurrentRow?.DataBoundItem is WorkflowActionItem current) return current;
        return null;
    }

    private WorkflowDashboardItem? GetSelectedWorkflowDashboardItem()
    {
        if (_workflowDashboardGrid.SelectedRows.Count > 0 && _workflowDashboardGrid.SelectedRows[0].DataBoundItem is WorkflowDashboardItem selected) return selected;
        if (_workflowDashboardGrid.CurrentRow?.DataBoundItem is WorkflowDashboardItem current) return current;
        return null;
    }

    private ProjectEvidenceItem? GetSelectedProjectEvidenceItem()
    {
        if (_workflowEvidenceGrid.SelectedRows.Count > 0 && _workflowEvidenceGrid.SelectedRows[0].DataBoundItem is ProjectEvidenceItem selected) return selected;
        if (_workflowEvidenceGrid.CurrentRow?.DataBoundItem is ProjectEvidenceItem current) return current;
        return null;
    }

    private void ShowSelectedWorkflowActionItem()
    {
        var item = GetSelectedWorkflowActionItem();
        if (item == null)
        {
            _workflowGuideInfoBox.Text = BuildWorkflowGuideOverviewText();
            return;
        }

        _workflowGuideInfoBox.Text =
            $"优先行动 #{item.PriorityNo}    级别：{item.Level}    关联工作台：{item.TargetArea}\r\n" +
            $"建议行动：{item.Action}\r\n" +
            $"预期结果：{item.ExpectedResult}\r\n" +
            $"安全说明：{item.SafetyNote}\r\n\r\n" +
            $"备注提示：{item.NoteHint}\r\n\r\n" +
            "提示：双击本行动，或点击“处理选中行动”，会跳转到对应页面并尽量自动筛选/定位第一条风险对象；点击“处理并建对象备注”会处理后为定位到的具体对象创建备注；点击“为行动建备注”会创建行动级备注。两类备注都不写入游戏文件。\r\n\r\n" +
            BuildWorkflowGuideOverviewText();
    }

    private void ShowSelectedWorkflowDashboardItem()
    {
        var item = GetSelectedWorkflowDashboardItem();
        if (item == null)
        {
            _workflowGuideInfoBox.Text = BuildWorkflowGuideOverviewText();
            return;
        }

        _workflowGuideInfoBox.Text =
            $"工作台：{item.Area}    级别：{item.Level}    当前值：{item.Value}\r\n" +
            $"摘要：{item.Summary}\r\n" +
            $"建议：{item.Suggestion}\r\n" +
            $"相关页面：{item.RelatedPage}\r\n" +
            $"证据/路径：{item.Evidence}\r\n\r\n" +
            BuildWorkflowGuideOverviewText();
    }

    private void ShowSelectedProjectEvidenceItem()
    {
        var item = GetSelectedProjectEvidenceItem();
        if (item == null)
        {
            _workflowGuideInfoBox.Text = BuildWorkflowGuideOverviewText();
            return;
        }

        SetLastCreatorNoteContext(
            "报告/发布证据",
            BuildProjectEvidenceCreatorNoteTargetKey(item),
            $"{item.Kind}：{item.FileName}",
            "从制作向导最近报告/发布证据表抓取；该证据文件不参与游戏运行。",
            $"证据类型：{item.Kind}\r\n文件：{item.FullPath}\r\n中文说明：{item.Annotation}\r\n用途：{item.SuggestedUse}\r\n复查结论：\r\n实机验证：");
        _workflowGuideInfoBox.Text =
            $"报告/发布证据：{item.Kind}    分类：{item.Category}    时间：{item.LastWriteTimeText}    大小：{item.SizeText}\r\n" +
            $"文件：{item.FileName}\r\n" +
            $"路径：{item.FullPath}\r\n" +
            $"中文说明：{item.Annotation}\r\n" +
            $"创作者用途：{item.SuggestedUse}\r\n" +
            $"安全说明：{item.SafetyNote}\r\n\r\n" +
            "提示：双击本行或点击“打开选中证据”可直接打开；点击“定位证据文件”会在资源管理器中定位；也可以点击“创作者备注 -> 抓取当前选择”为该证据写复查备注。\r\n\r\n" +
            BuildWorkflowGuideOverviewText();
    }

    private void OpenSelectedProjectEvidence()
    {
        var item = GetSelectedProjectEvidenceItem();
        if (item == null)
        {
            MessageBox.Show(this, "请先在“最近报告/发布证据”表中选择一项。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        if (!File.Exists(item.FullPath))
        {
            MessageBox.Show(this, "证据文件不存在：" + item.FullPath, "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            RefreshProjectEvidence(updateStatus: false);
            return;
        }

        try
        {
            Process.Start(new ProcessStartInfo
            {
                FileName = item.FullPath,
                UseShellExecute = true
            });
            SetStatus("已打开证据文件：" + item.FileName);
        }
        catch
        {
            OpenFileLocation(item.FullPath);
        }
    }

    private void LocateSelectedProjectEvidence()
    {
        var item = GetSelectedProjectEvidenceItem();
        if (item == null)
        {
            MessageBox.Show(this, "请先在“最近报告/发布证据”表中选择一项。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        if (!File.Exists(item.FullPath))
        {
            MessageBox.Show(this, "证据文件不存在：" + item.FullPath, "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            RefreshProjectEvidence(updateStatus: false);
            return;
        }

        OpenFileLocation(item.FullPath);
    }

    private static string BuildProjectEvidenceCreatorNoteTargetKey(ProjectEvidenceItem item)
        => $"Evidence#{item.Kind}#{item.FileName}#{item.LastWriteTime:yyyyMMddHHmmss}";

    private void HandleSelectedWorkflowActionItem()
    {
        var action = GetSelectedWorkflowActionItem();
        if (action == null)
        {
            MessageBox.Show(this, "请先选择一个优先行动。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        if (action.TargetArea == "项目状态")
        {
            OpenProjectDialog();
            return;
        }

        var dashboardItem = _currentWorkflowDashboardItems.FirstOrDefault(x => x.Area == action.TargetArea);
        if (dashboardItem == null)
        {
            MessageBox.Show(this, $"没有找到关联工作台项：{action.TargetArea}", "提示", MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        var selected = SelectGridRow<WorkflowDashboardItem>(_workflowDashboardGrid, x => x.Area == dashboardItem.Area);
        if (!selected)
        {
            _workflowDashboardGrid.ClearSelection();
        }

        HandleSelectedWorkflowDashboardItem();
    }

    private void HandleSelectedWorkflowActionAndCreateLocatedNote()
    {
        var action = GetSelectedWorkflowActionItem();
        if (action == null)
        {
            MessageBox.Show(this, "请先选择一个优先行动。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        HandleSelectedWorkflowActionItem();
        if (_project == null) return;

        var context = BuildCreatorNoteContextFromSelection();
        if (context.Scope == "全局项目")
        {
            MessageBox.Show(this, "已处理行动，但暂未定位到可生成对象备注的具体数据行。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        CreateCreatorNoteFromContext(
            context,
            $"从优先行动“{action.TargetArea}”处理后定位对象创建。",
            $"{action.Level},对象证据,待办");
    }

    private void CreateCreatorNoteFromSelectedWorkflowAction()
    {
        if (_project == null)
        {
            MessageBox.Show(this, "请先加载项目。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        var action = GetSelectedWorkflowActionItem();
        if (action == null)
        {
            MessageBox.Show(this, "请先选择一个优先行动。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        try
        {
            var targetKey = ProjectWorkflowGuideService.BuildWorkflowActionTargetKey(action.TargetArea);
            var saved = _creatorNoteService.Upsert(_project, new CreatorNote
            {
                Scope = "工作台行动",
                TargetKey = targetKey,
                Title = $"行动#{action.PriorityNo}：{action.TargetArea}",
                Tags = $"{action.Level},工作台行动,待办",
                SourceHint = "从制作向导优先行动表创建。",
                Content =
                    $"关联工作台：{action.TargetArea}\r\n" +
                    $"建议行动：{action.Action}\r\n" +
                    $"预期结果：{action.ExpectedResult}\r\n" +
                    $"安全说明：{action.SafetyNote}\r\n\r\n" +
                    "处理记录：\r\n" +
                    "实机验证：\r\n" +
                    "回滚点/备份："
            });

            _currentCreatorNotes = _creatorNoteService.Load(_project);
            BindCreatorNoteRows(_currentCreatorNotes);
            SelectCreatorNoteById(saved.Id);
            SelectTabPageByText("创作者备注");
            _creatorNoteInfoBox.Text =
                "已为优先行动创建项目侧备注。\r\n" +
                "该备注只保存在 CCZModStudio_Notes，不写入游戏文件。\r\n\r\n" +
                _creatorNoteService.BuildSummary(_project, _currentCreatorNotes);
            SetStatus("已为优先行动创建创作者备注");
            RememberLocatedObjectContextForNotes();
            RefreshWorkflowGuide(updateStatus: false);
        }
        catch (Exception ex)
        {
            Log("为优先行动创建备注失败：" + ex);
            MessageBox.Show(this, ex.Message, "创建行动备注失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }

    private void RememberLocatedObjectContextForNotes()
    {
        var context = BuildCreatorNoteContextFromSelection();
        if (context.Scope == "全局项目" || string.IsNullOrWhiteSpace(context.TargetKey)) return;
        SetLastCreatorNoteContext(context.Scope, context.TargetKey, context.Title, context.SourceHint, context.ContentSeed);
    }

    private void CreateCreatorNoteFromContext(
        (string Scope, string TargetKey, string Title, string SourceHint, string ContentSeed) context,
        string sourceHint,
        string tags)
    {
        if (_project == null)
        {
            MessageBox.Show(this, "请先加载项目。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        var saved = _creatorNoteService.Upsert(_project, new CreatorNote
        {
            Scope = context.Scope,
            TargetKey = context.TargetKey,
            Title = context.Title,
            Tags = tags,
            SourceHint = sourceHint + " " + context.SourceHint,
            Content = context.ContentSeed
        });

        _currentCreatorNotes = _creatorNoteService.Load(_project);
        BindCreatorNoteRows(_currentCreatorNotes);
        SelectCreatorNoteById(saved.Id);
        SelectTabPageByText("创作者备注");
        _creatorNoteInfoBox.Text =
            "已为当前定位对象创建项目侧备注。\r\n" +
            "该备注只保存在 CCZModStudio_Notes，不写入游戏文件。\r\n\r\n" +
            _creatorNoteService.BuildSummary(_project, _currentCreatorNotes);
        SetStatus("已为当前定位对象创建创作者备注");
        RefreshWorkflowGuide(updateStatus: false);
    }

    private void HandleSelectedWorkflowDashboardItem()
    {
        var item = GetSelectedWorkflowDashboardItem();
        if (item == null)
        {
            MessageBox.Show(this, "请先选择一个工作台项目。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        try
        {
            switch (item.Area)
            {
                case "写入模式":
                    if (_project?.IsTestCopy == true)
                    {
                        SelectTabPageByText("测试副本差异/发布");
                        if (_currentProjectDiffItems.Count == 0) AnalyzeProjectDiff();
                    }
                    else
                    {
                        CreateTestCopy();
                    }
                    break;

                case "数据表与中文注释":
                    SelectTabPageByText("数据表编辑");
                    if (_tableList.Items.Count > 0 && _tableList.SelectedIndex < 0)
                    {
                        _tableList.SelectedIndex = 0;
                    }
                    SetStatus("已跳转到数据表编辑页，请选择表和字段查看中文注释。");
                    break;

                case "项目体检":
                    SelectTabPageByText("项目体检/发布检查");
                    if (_currentAuditItems.Count == 0) RunProjectAudit();
                    SelectFirstAuditRiskRow();
                    break;

                case "资源诊断":
                    SelectTabPageByText("资源诊断");
                    if (_currentResourceDiagnostics.Count == 0)
                    {
                        RunResourceDiagnostics();
                    }
                    else
                    {
                        ApplyResourceDiagnosticDashboardFilter();
                    }
                    break;

                case "创作者备注":
                    SelectTabPageByText("创作者备注");
                    if (_currentCreatorNotes.Count == 0) LoadCreatorNotes(silent: true);
                    ApplyCreatorNoteDashboardFilter(item);
                    break;

                case "差异与备份":
                    if (_project?.IsTestCopy == true)
                    {
                        SelectTabPageByText("测试副本差异/发布");
                        if (_currentProjectDiffItems.Count == 0) AnalyzeProjectDiff();
                        else ApplyProjectDiffDashboardFilter();
                    }
                    else
                    {
                        SelectTabPageByText("测试副本差异/发布");
                        _projectDiffInfoBox.Text = "当前项目可直接编辑；测试副本差异需要先创建测试副本作为对照。备份历史仍可直接查看和还原。";
                        MessageBox.Show(this, "测试副本差异需要带 _CCZModStudio_TestCopy.txt 标记的目录；当前项目的备份历史可直接查看。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    }
                    break;

                case "关卡地图联动":
                    SelectTabPageByText("关卡地图联动");
                    if (_currentScenarioMapLinks.Count == 0) LoadScenarioMapLinks();
                    ApplyScenarioMapDashboardFilter();
                    break;

                case "SV高风险命令":
                    SelectTabPageByText("R/S eex高级探针");
                    EnsureScenarioStructureForDashboard();
                    ApplyScenarioHighRiskDashboardFilter();
                    break;

                case "EEX/Ls/Hexzmap探针":
                    HandleProbeDashboardItem();
                    break;

                case "最近报告/发布证据":
                    HandleLatestReportDashboardItem(item);
                    break;

                default:
                    if (!string.IsNullOrWhiteSpace(item.RelatedPage))
                    {
                        SelectTabPageByText(item.RelatedPage.Split('/')[0].Trim());
                    }
                    break;
            }

            RememberLocatedObjectContextForNotes();
            RefreshWorkflowGuide(updateStatus: false);
        }
        catch (Exception ex)
        {
            Log("处理工作台项目失败：" + ex);
            MessageBox.Show(this, ex.Message, "处理工作台项目失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }

    private void ApplyResourceDiagnosticDashboardFilter()
    {
        if (_currentResourceDiagnostics.Count == 0) return;
        var severity = _currentResourceDiagnostics.Any(x => x.Severity == "Error")
            ? "Error"
            : _currentResourceDiagnostics.Any(x => x.Severity == "Warn")
                ? "Warn"
                : "全部";
        SelectComboValueOrFirst(_resourceDiagnosticSeverityFilterCombo, severity);
        SelectComboValueOrFirst(_resourceDiagnosticCategoryFilterCombo, "全部");
        _resourceDiagnosticSearchBox.Clear();
        ApplyResourceDiagnosticFilter();
        var found = SelectGridRow<ResourceDiagnosticItem>(_resourceDiagnosticGrid, row =>
            severity == "全部" || row.Severity.Equals(severity, StringComparison.OrdinalIgnoreCase));
        if (found) ShowSelectedResourceDiagnostic();
        SetStatus(severity == "全部"
            ? "已跳转到资源诊断页并显示全部诊断项。"
            : $"已跳转到资源诊断页，已筛选并定位第一条 {severity} 项。");
    }

    private void ApplyCreatorNoteDashboardFilter(WorkflowDashboardItem item)
    {
        var keyword = item.Value.Contains("待办 0", StringComparison.Ordinal)
            ? item.Value.Contains("风险 0", StringComparison.Ordinal) ? string.Empty : "风险"
            : "待办";
        _creatorNoteSearchBox.Text = keyword;
        if (string.IsNullOrWhiteSpace(keyword))
        {
            ClearCreatorNoteFilter();
            SetStatus("已跳转到创作者备注页并显示全部备注。");
        }
        else
        {
            ApplyCreatorNoteFilter();
            var found = SelectGridRow<CreatorNote>(_creatorNoteGrid, note =>
                ContainsKeyword(note.Tags, keyword) ||
                ContainsKeyword(note.Title, keyword) ||
                ContainsKeyword(note.Content, keyword) ||
                ContainsKeyword(note.SourceHint, keyword));
            if (found) ShowSelectedCreatorNote();
            SetStatus($"已跳转到创作者备注页并筛选：{keyword}");
        }
    }

    private void ApplyProjectDiffDashboardFilter()
    {
        if (_currentProjectDiffItems.Count == 0) return;
        var status = _currentProjectDiffItems.Any(x => x.Status == "已修改")
            ? "已修改"
            : _currentProjectDiffItems.Any(x => x.Status == "新增")
                ? "新增"
                : _currentProjectDiffItems.Any(x => x.Status == "缺失")
                    ? "缺失"
                    : "全部";
        SelectComboValueOrFirst(_projectDiffStatusFilterCombo, status);
        _projectDiffSearchBox.Clear();
        ApplyProjectDiffFilter();
        var found = SelectGridRow<ProjectDiffItem>(_projectDiffGrid, row =>
            status == "全部" || row.Status.Equals(status, StringComparison.OrdinalIgnoreCase));
        if (found)
        {
            ShowSelectedProjectDiffItem();
            ShowBackupTimelineForSelectedProjectDiff();
            SelectFirstBackupHistoryRow();
            SelectTabPageByText("备份历史/回滚");
        }
        SetStatus(status == "全部"
            ? "已跳转到测试副本差异页并显示全部差异。"
            : $"已筛选并定位第一条“{status}”差异，同时联动备份时间线。");
    }

    private void ApplyScenarioMapDashboardFilter()
    {
        if (_currentScenarioMapLinks.Count == 0) return;
        _scenarioMapLinksIncompleteOnly.Checked = _currentScenarioMapLinks.Any(ScenarioMapLinkIsIncomplete);
        SelectComboValueOrFirst(_scenarioMapLinkStatusFilterCombo, "全部");
        _scenarioMapLinkSearchBox.Clear();
        ApplyScenarioMapLinkFilter();
        var found = SelectGridRow<ScenarioMapLinkInfo>(_scenarioMapLinkGrid, ScenarioMapLinkIsIncomplete)
                    || SelectGridRow<ScenarioMapLinkInfo>(_scenarioMapLinkGrid, row => row.Status == "完整候选")
                    || SelectGridRow<ScenarioMapLinkInfo>(_scenarioMapLinkGrid, _ => true);
        if (found) ShowSelectedScenarioMapLink();
        SetStatus(found
            ? "已跳转到关卡地图联动页，并定位第一条不完整/候选联动。"
            : "已跳转到关卡地图联动页。");
    }

    private void EnsureScenarioStructureForDashboard()
    {
        if (_currentScenarioStructureResult != null) return;
        if (_currentScenarioFiles.Count == 0)
        {
            LoadScenarioFiles();
        }

        if (_scenarioFileGrid.CurrentRow?.DataBoundItem is not ScenarioFileInfo)
        {
            var found = SelectGridRow<ScenarioFileInfo>(_scenarioFileGrid, row => row.Kind == "标准关卡")
                        || SelectGridRow<ScenarioFileInfo>(_scenarioFileGrid, _ => true);
            if (!found) return;
        }

        BuildSelectedScenarioStructure();
    }

    private void ApplyScenarioHighRiskDashboardFilter()
    {
        if (_currentScenarioStructureResult == null) return;
        _scenarioStructureHighRiskOnly.Checked = true;
        _scenarioStructureTemplatesOnly.Checked = false;
        _scenarioStructureTextOnly.Checked = false;
        _scenarioStructureMapOnly.Checked = false;
        _scenarioStructureFilterBox.Clear();
        ApplyScenarioStructureFilter();
        var found = SelectGridRow<ScenarioStructureRow>(_scenarioStructureGrid, row => _scenarioStructureFilterService.IsHighRisk(row))
                    || SelectGridRow<ScenarioStructureRow>(_scenarioStructureGrid, _ => true);
        if (_scenarioStructureGrid.CurrentRow?.DataBoundItem is ScenarioStructureRow selected)
        {
            SelectScenarioStructureTreeNode(selected);
            _scenarioStructureNodeInfoBox.Text = BuildScenarioStructureNodeDetail(selected);
        }

        SetStatus(found
            ? "已跳转到 R/S eex 结构草图，并定位第一条高风险/需核对命令。"
            : "已跳转到 R/S eex 结构草图。");
    }

    private void HandleProbeDashboardItem()
    {
        if (_currentHexzmapProbe == null)
        {
            LoadHexzmapProbe();
        }

        if (_currentHexzmapProbe != null && _currentHexzmapProbe.Blocks.Any(x => !string.IsNullOrWhiteSpace(x.UnknownTerrainIds)))
        {
            SelectTabPageByText("Hexzmap地形探针");
            var foundHex = SelectGridRow<HexzmapBlockInfo>(_hexzmapGrid, block => !string.IsNullOrWhiteSpace(block.UnknownTerrainIds))
                           || SelectGridRow<HexzmapBlockInfo>(_hexzmapGrid, _ => true);
            if (foundHex) ShowSelectedHexzmapBlock();
            SetStatus("已跳转到 Hexzmap 地形探针，并定位未知地形 ID 候选块。");
            return;
        }

        if (_currentEexArchives.Count == 0)
        {
            LoadEexArchives();
        }

        if (_currentEexArchives.Count > 0)
        {
            SelectTabPageByText("EEX资源探针");
            var foundEex = SelectGridRow<EexArchiveInfo>(_eexArchiveGrid, item => !item.MagicValid)
                           || SelectGridRow<EexArchiveInfo>(_eexArchiveGrid, _ => true);
            if (foundEex) ShowSelectedEexArchive();
            SetStatus("已跳转到 EEX 资源探针，并定位第一条 EEX 候选资源。");
            return;
        }

        if (_currentLsResources.Count == 0)
        {
            LoadLsResources();
        }

        SelectTabPageByText("Ls/E5地图资源探针");
        var foundLs = SelectGridRow<LsResourceInfo>(_lsResourceGrid, item => !item.MagicValid)
                      || SelectGridRow<LsResourceInfo>(_lsResourceGrid, _ => true);
        if (foundLs) ShowSelectedLsResource();
        SetStatus("已跳转到 Ls/E5 资源探针。");
    }

    private void HandleLatestReportDashboardItem(WorkflowDashboardItem item)
    {
        if (_currentProjectEvidenceItems.Count == 0)
        {
            RefreshProjectEvidence(updateStatus: false);
        }

        var evidence = _currentProjectEvidenceItems.FirstOrDefault(x => x.FullPath.Equals(item.Evidence, StringComparison.OrdinalIgnoreCase))
                       ?? _currentProjectEvidenceItems.OrderByDescending(x => x.LastWriteTime).FirstOrDefault();
        if (evidence != null && File.Exists(evidence.FullPath))
        {
            SelectTabPageByText("制作向导");
            var selected = SelectGridRow<ProjectEvidenceItem>(_workflowEvidenceGrid, x => x.FullPath.Equals(evidence.FullPath, StringComparison.OrdinalIgnoreCase));
            if (selected)
            {
                ShowSelectedProjectEvidenceItem();
            }
            OpenSelectedProjectEvidence();
            return;
        }

        SelectTabPageByText("测试副本差异/发布");
        if (_project != null)
        {
            WriteProjectDeliveryReport();
        }
        else
        {
            MessageBox.Show(this, "请先加载项目，再生成综合报告。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Information);
        }
    }

    private void SelectFirstAuditRiskRow()
    {
        if (_currentAuditItems.Count == 0) return;
        var found = SelectGridRow<ProjectAuditItem>(_auditGrid, row => row.Severity == "Error")
                    || SelectGridRow<ProjectAuditItem>(_auditGrid, row => row.Severity == "Warn")
                    || SelectGridRow<ProjectAuditItem>(_auditGrid, _ => true);
        SetStatus(found ? "已跳转到项目体检页，并定位第一条错误/警告项。" : "已跳转到项目体检页。");
    }

    private void SelectFirstBackupHistoryRow()
    {
        var found = SelectGridRow<BackupHistoryItem>(_backupHistoryGrid, row => row.Restorable)
                    || SelectGridRow<BackupHistoryItem>(_backupHistoryGrid, _ => true);
        if (found) ShowSelectedBackupHistoryItem();
    }

    private void ShowSelectedWorkflowStep()
    {
        var step = GetSelectedWorkflowStep();
        if (step == null)
        {
            _workflowGuideInfoBox.Text = _workflowGuideService.BuildSummary(_project, _currentWorkflowSteps, _currentWorkflowDashboardItems);
            return;
        }

        _workflowGuideInfoBox.Text =
            $"第 {step.StepNo} 步：{step.Title}\r\n" +
            $"阶段：{step.Stage}    当前状态：{step.Status}    相关页面：{step.RelatedPage}\r\n" +
            $"建议操作：{step.RecommendedAction}\r\n" +
            $"为什么重要：{step.WhyItMatters}\r\n" +
            $"安全说明：{step.SafetyNote}\r\n\r\n" +
            _workflowGuideService.BuildSummary(_project, _currentWorkflowSteps, _currentWorkflowDashboardItems);
    }

    private void RefreshTableList()
    {
        IEnumerable<HexTableDefinition> query = _tables;
        if (!_showAllTables.Checked)
        {
            query = query.Where(t => t.Enabled && t.Version == "6.5");
        }

        var selectedId = (_tableList.SelectedItem as HexTableDefinition)?.Id;
        var list = query.OrderBy(t => t.Id).ToList();
        _tableList.DataSource = list;
        if (selectedId.HasValue)
        {
            var match = list.FirstOrDefault(t => t.Id == selectedId.Value);
            if (match != null) _tableList.SelectedItem = match;
        }
    }

    private void LoadSelectedTable()
    {
        if (_project == null || _tableList.SelectedItem is not HexTableDefinition table) return;

        try
        {
            Cursor = Cursors.WaitCursor;
            var result = _tableReader.Read(_project, table, _tables);
            _currentTableResult = result;
            _dataGrid.DataSource = result.Data;
            _tableColumnFilterBox.Clear();
            _dangerTableColumnsOnly.Checked = false;
            _tableRowFilterBox.Clear();
            _changedTableRowsOnly.Checked = false;
            _tableRowSearchVisibleColumnsOnly.Checked = true;
            ClearCurrentTableReferenceTarget();
            ConfigureDataGrid(result);
            ConfigureChartColumns(result.Data);
            var canEdit = CanEditTable(result);
            _fieldAnnotationBox.Text = _fieldAnnotationService.BuildTableSummary(table, result.Validation, canEdit);
            LogTableValidation(result.Validation);
            SetStatus(result.Validation.IsUsable
                ? $"已读取：{table.TableName}，{result.Data.Rows.Count} 行。当前项目可编辑，保存前会自动备份。"
                : $"表不可读取：{table.TableName}，请查看诊断。");
        }
        catch (Exception ex)
        {
            Log($"读取表失败：{table.TableName}\r\n{ex}");
            SetStatus("读取失败");
        }
        finally
        {
            RefreshWorkflowGuide(updateStatus: false);
            Cursor = Cursors.Default;
        }
    }

    private void ConfigureDataGrid(TableReadResult result)
    {
        var canEdit = CanEditTable(result);
        _dataGrid.ReadOnly = !canEdit;
        _saveTableButton.Enabled = canEdit;
        _exportCsvButton.Enabled = result.Validation.IsUsable && result.Data.Rows.Count > 0;
        _importCsvButton.Enabled = canEdit;
        _filterTableColumnsButton.Enabled = result.Validation.IsUsable && result.Data.Columns.Count > 0;
        _clearTableColumnFilterButton.Enabled = result.Validation.IsUsable && result.Data.Columns.Count > 0;
        _dangerTableColumnsOnly.Enabled = result.Validation.IsUsable && result.Data.Columns.Count > 0;
        _exportFieldAnnotationsButton.Enabled = result.Validation.IsUsable && result.Table.Fields.Count > 0;
        _exportVisibleColumnsCsvButton.Enabled = result.Validation.IsUsable && result.Data.Rows.Count > 0;
        _visibleColumnsCsvWithNotes.Enabled = result.Validation.IsUsable && result.Data.Rows.Count > 0;
        _filterTableRowsButton.Enabled = result.Validation.IsUsable && result.Data.Rows.Count > 0;
        _clearTableRowFilterButton.Enabled = result.Validation.IsUsable && result.Data.Rows.Count > 0;
        _changedTableRowsOnly.Enabled = result.Validation.IsUsable && result.Data.Rows.Count > 0;
        _tableRowSearchVisibleColumnsOnly.Enabled = result.Validation.IsUsable && result.Data.Rows.Count > 0;

        foreach (DataGridViewColumn column in _dataGrid.Columns)
        {
            column.ReadOnly = !canEdit || column.Index == 0;
            if (column.Index == 0)
            {
                column.HeaderText = "ID\n行号/编号";
                column.ToolTipText = "工具生成的行号/编号，用于和原版数据下标对应；不直接写入二进制。";
            }
            if (column.DataPropertyName is { Length: > 0 } propertyName &&
                result.Data.Columns.Contains(propertyName) &&
                result.Data.Columns[propertyName]!.ExtendedProperties["FieldDefinition"] is HexFieldDefinition field &&
                !field.ConsumesBytes)
            {
                column.ReadOnly = true;
            }
            if (column.DataPropertyName is { Length: > 0 } fieldProperty &&
                result.Data.Columns.Contains(fieldProperty) &&
                result.Data.Columns[fieldProperty]!.ExtendedProperties["FieldDefinition"] is HexFieldDefinition fieldDefinition)
            {
                column.HeaderText = fieldProperty + "\n" + _fieldAnnotationService.BuildShortFieldAnnotation(result.Table, fieldDefinition);
                column.ToolTipText = _fieldAnnotationService.BuildFieldAnnotation(result.Table, fieldDefinition);
            }
        }

        RefreshDataGridRowStyles();
    }

    private static bool CanEditTable(TableReadResult result)
        => result.Validation.IsUsable &&
           !result.Table.ReadOnly &&
           !ItemEffectNameReader.IsItemEffectNameTable(result.Table);

    private void ShowSelectedDataCellAnnotation(int rowIndex, int columnIndex)
    {
        if (_currentTableResult == null || rowIndex < 0 || columnIndex < 0)
        {
            ClearCurrentTableReferenceTarget();
            return;
        }

        if (columnIndex >= _dataGrid.Columns.Count || rowIndex >= _dataGrid.Rows.Count)
        {
            ClearCurrentTableReferenceTarget();
            return;
        }

        var column = _dataGrid.Columns[columnIndex];
        if (columnIndex == 0)
        {
            _fieldAnnotationBox.Text = _fieldAnnotationService.BuildTableSummary(
                _currentTableResult.Table,
                _currentTableResult.Validation,
                CanEditTable(_currentTableResult));
            ClearCurrentTableReferenceTarget("当前选中的是 ID 列；请选择具体字段查看跨表引用。");
            return;
        }

        var propertyName = column.DataPropertyName;
        if (string.IsNullOrWhiteSpace(propertyName) ||
            !_currentTableResult.Data.Columns.Contains(propertyName) ||
            _currentTableResult.Data.Columns[propertyName]!.ExtendedProperties["FieldDefinition"] is not HexFieldDefinition field)
        {
            ClearCurrentTableReferenceTarget();
            return;
        }

        var row = _dataGrid.Rows[rowIndex];
        var rowId = row.Cells[0].Value is null ? rowIndex : Convert.ToInt32(row.Cells[0].Value, CultureInfo.InvariantCulture);
        var value = row.Cells[columnIndex].Value;
        var annotation = _fieldAnnotationService.BuildCellAnnotation(_currentTableResult.Table, field, rowId, value);
        var targetKey = BuildTableCellCreatorNoteTargetKey(_currentTableResult.Table.TableName, rowId, field.ColumnName);
        SetLastCreatorNoteContext(
            "数据表单元格",
            targetKey,
            $"{_currentTableResult.Table.TableName} / ID {rowId} / {field.ColumnName}",
            $"从数据表编辑页抓取；当前值={Convert.ToString(value, CultureInfo.InvariantCulture) ?? string.Empty}",
            $"用途/修改理由：\r\n风险：\r\n实机验证：\r\n当前值：{Convert.ToString(value, CultureInfo.InvariantCulture) ?? string.Empty}");
        UpdateCurrentTableReferenceNavigation(_currentTableResult.Table, field, value, rowId);
        _fieldAnnotationBox.Text = annotation
                                   + BuildImageResourceEvidence(field.ColumnName, value)
                                   + BuildTableReferenceEvidence(_currentTableResult.Table, field, value, rowId)
                                   + BuildRelatedCreatorNotesText("数据表单元格", targetKey);
    }

    private static string BuildTableCellCreatorNoteTargetKey(string tableName, int rowId, string fieldName)
        => BuildTableCellCreatorNoteTargetKey(tableName, rowId.ToString(CultureInfo.InvariantCulture), fieldName);

    private static string BuildTableCellCreatorNoteTargetKey(string tableName, string rowId, string fieldName)
        => $"{tableName}#ID={rowId}#字段={fieldName}";

    private string BuildTableReferenceEvidence(HexTableDefinition table, HexFieldDefinition field, object? value, int rowId)
    {
        if (_project == null || _tables.Count == 0)
        {
            return string.Empty;
        }

        try
        {
            return _tableReferenceLookupService.BuildCellReferenceEvidence(_project, _tables, table, field, value, rowId);
        }
        catch (Exception ex)
        {
            Log("\u8de8\u8868\u5f15\u7528\u89e3\u91ca\u5931\u8d25\uff1a" + ex.Message);
            return "\r\n\r\n\u8de8\u8868\u5f15\u7528\u89e3\u91ca\uff1a\u5f53\u524d\u5b57\u6bb5\u53ef\u80fd\u5173\u8054\u5176\u4ed6\u8868\uff0c\u4f46\u672c\u6b21\u89e3\u6790\u5931\u8d25\u3002\u5efa\u8bae\u4fdd\u7559\u539f\u503c\u5e76\u7ed3\u5408\u539f\u5de5\u5177\u9a8c\u8bc1\u3002";
        }
    }

    private void UpdateCurrentTableReferenceNavigation(HexTableDefinition table, HexFieldDefinition field, object? value, int rowId)
    {
        if (_project == null || _tables.Count == 0)
        {
            ClearCurrentTableReferenceTarget();
            return;
        }

        try
        {
            var target = _tableReferenceLookupService.ResolveCellReferenceTarget(_project, _tables, table, field, value, rowId);
            _currentTableReferenceTarget = target;
            _jumpTableReferenceButton.Enabled = target.CanNavigate;
            _tableReferenceNavigationBox.Text = target.IsRecognized
                ? (target.CanNavigate
                    ? target.Summary
                    : target.Summary + (string.IsNullOrWhiteSpace(target.SafetyNote) ? string.Empty : "；提示：" + target.SafetyNote))
                : target.Summary;
        }
        catch (Exception ex)
        {
            Log("数据表引用导航解析失败：" + ex.Message);
            ClearCurrentTableReferenceTarget("跨表引用导航解析失败；请查看字段说明并结合原工具验证。");
        }
    }

    private void ClearCurrentTableReferenceTarget(string text = "选中引用字段后显示可跳转目标。")
    {
        _currentTableReferenceTarget = null;
        _jumpTableReferenceButton.Enabled = false;
        _tableReferenceNavigationBox.Text = text;
    }

    private void JumpCurrentTableReferenceTarget()
    {
        var target = _currentTableReferenceTarget;
        if (target == null || !target.CanNavigate)
        {
            MessageBox.Show(this, "当前单元格没有可跳转的跨表目标。请先选择人物职业、物品槽位、装备特效号、行对齐说明等已识别字段。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        if (SelectDataTableCell(target.TargetTableName, target.TargetRowId, target.TargetFieldName))
        {
            SetStatus($"已跳转到引用目标：{target.TargetTableName} / ID={target.TargetRowId} / {target.TargetFieldName}");
            return;
        }

        MessageBox.Show(this,
            $"未能定位引用目标：{target.TargetTableName} / ID={target.TargetRowId} / {target.TargetFieldName}\r\n{target.SafetyNote}",
            "未找到引用目标",
            MessageBoxButtons.OK,
            MessageBoxIcon.Information);
    }

    private string BuildImageResourceEvidence(string columnName, object? value)
    {
        if (_project == null || value == null || value == DBNull.Value)
        {
            return string.Empty;
        }

        var prefix = columnName switch
        {
            "R\u5f62\u8c61\u7f16\u53f7" => "R",
            "S\u5f62\u8c61\u7f16\u53f7" => "S",
            _ when columnName.Contains("R\u5f62\u8c61", StringComparison.Ordinal) => "R",
            _ when columnName.Contains("S\u5f62\u8c61", StringComparison.Ordinal) => "S",
            _ => string.Empty
        };

        if (string.IsNullOrWhiteSpace(prefix) ||
            !int.TryParse(Convert.ToString(value, CultureInfo.InvariantCulture), NumberStyles.Integer, CultureInfo.InvariantCulture, out var id))
        {
            return string.Empty;
        }

        var fileName = ImageAssignmentService.GetImageResourceFileName(prefix, id);
        var path = ImageAssignmentService.GetImageResourcePath(_project, prefix, id);
        var status = ImageAssignmentService.GetImageResourceStatus(_project, prefix, id);
        if (!File.Exists(path))
        {
            return $"\r\n\r\n\u8d44\u6e90\u5b9e\u8bc1\u68c0\u67e5\uff1a{status}\r\n\u671f\u671b\u8def\u5f84\uff1a{path}\r\n\u5efa\u8bae\uff1a\u82e5\u8fd9\u662f\u5b9e\u9645\u8981\u4f7f\u7528\u7684\u4eba\u7269\u5f62\u8c61\uff0c\u8bf7\u8865\u9f50 RS \u8d44\u6e90\u6216\u6539\u6210\u5df2\u5b58\u5728\u7f16\u53f7\u3002";
        }

        var info = new FileInfo(path);
        return $"\r\n\r\n\u8d44\u6e90\u5b9e\u8bc1\u68c0\u67e5\uff1a{status}\r\n\u8def\u5f84\uff1a{path}\r\n\u5927\u5c0f\uff1a{info.Length:N0} \u5b57\u8282\uff0c\u4fee\u6539\u65f6\u95f4\uff1a{info.LastWriteTime:yyyy-MM-dd HH:mm:ss}";
    }

    private void ApplyTableColumnFilter()
    {
        if (_currentTableResult == null)
        {
            return;
        }

        var keyword = _tableColumnFilterBox.Text.Trim();
        var dangerOnly = _dangerTableColumnsOnly.Checked;
        var visibleCount = 0;

        foreach (DataGridViewColumn column in _dataGrid.Columns)
        {
            if (column.Index == 0)
            {
                column.Visible = true;
                continue;
            }

            var visible = true;
            var propertyName = column.DataPropertyName;
            HexFieldDefinition? field = null;
            if (!string.IsNullOrWhiteSpace(propertyName) &&
                _currentTableResult.Data.Columns.Contains(propertyName) &&
                _currentTableResult.Data.Columns[propertyName]!.ExtendedProperties["FieldDefinition"] is HexFieldDefinition fieldDefinition)
            {
                field = fieldDefinition;
            }

            if (dangerOnly)
            {
                visible = field != null && _fieldAnnotationService.IsHighRiskField(_currentTableResult.Table, field);
            }

            if (visible && !string.IsNullOrWhiteSpace(keyword))
            {
                var haystack = string.Join("\n",
                    column.DataPropertyName,
                    column.HeaderText,
                    column.ToolTipText,
                    field == null ? string.Empty : _fieldAnnotationService.BuildShortFieldAnnotation(_currentTableResult.Table, field),
                    field == null ? string.Empty : _fieldAnnotationService.BuildFieldAnnotation(_currentTableResult.Table, field));
                visible = haystack.IndexOf(keyword, StringComparison.CurrentCultureIgnoreCase) >= 0;
            }

            column.Visible = visible;
            if (visible) visibleCount++;
        }

        SetStatus($"数据表列筛选：显示 {visibleCount}/{Math.Max(0, _dataGrid.Columns.Count - 1)} 个字段列");
    }

    private void ClearTableColumnFilter()
    {
        _tableColumnFilterBox.Clear();
        _dangerTableColumnsOnly.Checked = false;
        foreach (DataGridViewColumn column in _dataGrid.Columns)
        {
            column.Visible = true;
        }

        if (_currentTableResult != null)
        {
            SetStatus($"已显示全部字段列：{Math.Max(0, _dataGrid.Columns.Count - 1)} 列");
        }
    }

    private void ApplyTableRowFilter()
    {
        if (_currentTableResult == null)
        {
            return;
        }

        _dataGrid.EndEdit();
        var keyword = _tableRowFilterBox.Text.Trim();
        var changedOnly = _changedTableRowsOnly.Checked;
        var visibleCount = 0;
        _dataGrid.CurrentCell = null;
        _dataGrid.SuspendLayout();
        try
        {
            foreach (DataGridViewRow gridRow in _dataGrid.Rows)
            {
                var row = TryGetDataRow(gridRow);
                if (row == null)
                {
                    gridRow.Visible = false;
                    continue;
                }

                var visible = true;
                if (changedOnly)
                {
                    visible = IsDataRowChanged(row);
                }

                if (visible && !string.IsNullOrWhiteSpace(keyword))
                {
                    var searchColumns = GetTableRowSearchColumns();
                    visible = searchColumns
                        .Any(column => (Convert.ToString(row[column], CultureInfo.InvariantCulture) ?? string.Empty)
                            .IndexOf(keyword, StringComparison.CurrentCultureIgnoreCase) >= 0);
                }

                gridRow.Visible = visible;
                if (visible) visibleCount++;
            }
        }
        finally
        {
            _dataGrid.ResumeLayout();
        }

        SetStatus($"数据表行筛选：显示 {visibleCount}/{_currentTableResult.Data.Rows.Count} 行");
    }

    private IReadOnlyList<DataColumn> GetTableRowSearchColumns()
    {
        if (_currentTableResult == null) return Array.Empty<DataColumn>();
        if (!_tableRowSearchVisibleColumnsOnly.Checked)
        {
            return _currentTableResult.Data.Columns.Cast<DataColumn>().ToList();
        }

        var visibleColumnNames = _dataGrid.Columns
            .Cast<DataGridViewColumn>()
            .Where(c => c.Visible && !string.IsNullOrWhiteSpace(c.DataPropertyName))
            .OrderBy(c => c.DisplayIndex)
            .Select(c => c.DataPropertyName)
            .Distinct(StringComparer.Ordinal)
            .Where(name => _currentTableResult.Data.Columns.Contains(name))
            .ToList();
        return visibleColumnNames.Count == 0
            ? _currentTableResult.Data.Columns.Cast<DataColumn>().ToList()
            : visibleColumnNames.Select(name => _currentTableResult.Data.Columns[name]!).ToList();
    }

    private void ClearTableRowFilter()
    {
        _tableRowFilterBox.Clear();
        _changedTableRowsOnly.Checked = false;
        foreach (DataGridViewRow row in _dataGrid.Rows)
        {
            row.Visible = true;
        }

        if (_currentTableResult != null)
        {
            SetStatus($"已显示全部数据行：{_currentTableResult.Data.Rows.Count} 行");
        }
        RefreshDataGridRowStyles();
    }

    private void ExportCurrentTableFieldAnnotations()
    {
        if (_project == null || _currentTableResult == null)
        {
            MessageBox.Show(this, "请先读取一个数据表。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        try
        {
            var currentTable = _currentTableResult.Table;
            var path = _fieldAnnotationService.ExportAnnotations(
                _project,
                currentTable,
                _currentTableResult.Validation,
                _currentTableResult.Data,
                field => _tableReferenceLookupService.BuildFieldReferenceHint(currentTable, field));
            Log("已导出字段注释：" + path);
            SetStatus("字段注释导出完成");
            MessageBox.Show(this, "字段注释导出完成：\r\n" + path, "完成", MessageBoxButtons.OK, MessageBoxIcon.Information);
        }
        catch (Exception ex)
        {
            Log("字段注释导出失败：" + ex);
            MessageBox.Show(this, ex.Message, "字段注释导出失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }

    private void ConfigureChartColumns(DataTable data)
    {
        var numericColumns = data.Columns
            .Cast<DataColumn>()
            .Where(c => c.ColumnName != "ID" && IsNumericColumn(data, c))
            .Select(c => c.ColumnName)
            .ToList();

        _chartColumnCombo.DataSource = numericColumns;
        _renderChartButton.Enabled = numericColumns.Count > 0;
        _tableChartBox.Image?.Dispose();
        _tableChartBox.Image = null;
        _tableChartInfoBox.Text = numericColumns.Count > 0 ? $"可绘制 {numericColumns.Count} 个数值列。" : "当前表未发现可绘制数值列。";
    }

    private static bool IsNumericColumn(DataTable data, DataColumn column)
    {
        var checkedRows = 0;
        foreach (DataRow row in data.Rows)
        {
            var text = Convert.ToString(row[column], CultureInfo.InvariantCulture);
            if (string.IsNullOrWhiteSpace(text)) continue;
            checkedRows++;
            if (!TryParseDouble(text, out _)) return false;
            if (checkedRows >= 200) break;
        }
        return checkedRows > 0;
    }

    private static bool TryParseDouble(string? text, out double value)
    {
        text = (text ?? string.Empty).Trim();
        if (text.StartsWith("0x", StringComparison.OrdinalIgnoreCase))
        {
            if (ulong.TryParse(text[2..], NumberStyles.HexNumber, CultureInfo.InvariantCulture, out var hex))
            {
                value = hex;
                return true;
            }
        }

        return double.TryParse(text, NumberStyles.Float | NumberStyles.AllowThousands, CultureInfo.InvariantCulture, out value);
    }

    private void SaveCurrentTable()
    {
        if (_project == null || _currentTableResult == null)
        {
            return;
        }

        if (!CanEditTable(_currentTableResult))
        {
            MessageBox.Show(this, "当前表不开放直接保存。装备特效名称表使用 00 分隔的变长字符串，请通过“宝物设定 -> 宝物特效”维护项目侧特效目录。", "不能保存", MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        _dataGrid.EndEdit();
        if (_currentTableResult.Data.GetChanges() == null)
        {
            MessageBox.Show(this, "当前表格没有检测到改动。", "无需保存", MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        var preview = BuildChangePreview(_currentTableResult.Data, maxItems: 40);
        if (MessageBox.Show(this,
                $"即将保存当前表到 MOD 项目：\r\n{_currentTableResult.Table.TableName}\r\n\r\n变更预览：\r\n{preview}\r\n\r\n保存前会自动备份目标文件，保存后会重新读取校验。是否继续？",
                "确认保存",
                MessageBoxButtons.YesNo,
                MessageBoxIcon.Question) != DialogResult.Yes)
        {
            return;
        }

        try
        {
            Cursor = Cursors.WaitCursor;
            var savedTable = _currentTableResult.Table;
            var result = _tableWriter.Save(_project, savedTable, _currentTableResult.Data);
            var verifyRead = _tableReader.Read(_project, savedTable, _tables);
            if (!verifyRead.Validation.IsUsable)
            {
                throw new InvalidOperationException("保存后重新读取失败，请查看诊断和备份。");
            }

            _currentTableResult = verifyRead;
            _dataGrid.DataSource = verifyRead.Data;
            ConfigureDataGrid(verifyRead);
            ConfigureChartColumns(verifyRead.Data);
            Log($"已保存表：{result.Table.TableName}");
            Log($"写入文件：{result.FilePath}");
            Log($"写入行数：{result.RowsWritten}，变化字节数：{result.ChangedBytes}");
            Log($"保存前备份：{result.BackupPath}");
            Log($"结构化报告：{result.ReportJsonPath}");
            SetStatus($"保存完成并已复读：变化 {result.ChangedBytes} 字节");
            MessageBox.Show(this,
                $"保存完成并已重新读取校验。\r\n变化字节数：{result.ChangedBytes}\r\n备份：{result.BackupPath}\r\n结构化报告：{result.ReportJsonPath}",
                "保存完成",
                MessageBoxButtons.OK,
                MessageBoxIcon.Information);
        }
        catch (Exception ex)
        {
            Log("保存失败：" + ex);
            MessageBox.Show(this, ex.Message, "保存失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
        finally
        {
            RefreshWorkflowGuide(updateStatus: false);
            Cursor = Cursors.Default;
        }
    }

    private void RenderCurrentTableChart()
    {
        if (_currentTableResult == null || _chartColumnCombo.SelectedItem is not string columnName)
        {
            return;
        }

        var values = new List<double>();
        foreach (DataRow row in _currentTableResult.Data.Rows)
        {
            var text = Convert.ToString(row[columnName], CultureInfo.InvariantCulture);
            if (TryParseDouble(text, out var value)) values.Add(value);
        }

        if (values.Count == 0)
        {
            _tableChartInfoBox.Text = "没有可绘制的数据。";
            return;
        }

        var bitmap = DrawHistogram(_currentTableResult.Table.TableName, columnName, values, _tableChartBox.Width, _tableChartBox.Height);
        var old = _tableChartBox.Image;
        _tableChartBox.Image = bitmap;
        old?.Dispose();
        _tableChartInfoBox.Text = $"数量 {values.Count}，最小 {values.Min():0.##}，最大 {values.Max():0.##}，平均 {values.Average():0.##}";
    }

    private static Bitmap DrawHistogram(string tableName, string columnName, IReadOnlyList<double> values, int width, int height)
    {
        width = Math.Max(640, width);
        height = Math.Max(220, height);
        var bitmap = new Bitmap(width, height);
        using var g = Graphics.FromImage(bitmap);
        g.Clear(Color.White);
        g.SmoothingMode = System.Drawing.Drawing2D.SmoothingMode.AntiAlias;

        using var textBrush = new SolidBrush(Color.FromArgb(35, 35, 35));
        using var axisPen = new Pen(Color.FromArgb(90, 90, 90));
        using var gridPen = new Pen(Color.FromArgb(230, 230, 230));
        using var barBrush = new SolidBrush(Color.FromArgb(64, 121, 191));
        using var titleFont = new Font("Microsoft YaHei UI", 10F, FontStyle.Bold);
        using var font = new Font("Microsoft YaHei UI", 8.5F);

        var plot = new Rectangle(54, 42, width - 80, height - 86);
        g.DrawString($"{tableName} - {columnName} 分布", titleFont, textBrush, 12, 10);

        var min = values.Min();
        var max = values.Max();
        var average = values.Average();
        if (Math.Abs(max - min) < 0.000001)
        {
            max = min + 1;
        }

        var binCount = Math.Clamp((int)Math.Ceiling(Math.Sqrt(values.Count)), 6, 24);
        var bins = new int[binCount];
        foreach (var value in values)
        {
            var index = (int)Math.Floor((value - min) / (max - min) * binCount);
            index = Math.Clamp(index, 0, binCount - 1);
            bins[index]++;
        }

        var maxCount = Math.Max(1, bins.Max());
        for (var i = 0; i <= 4; i++)
        {
            var y = plot.Bottom - (plot.Height * i / 4);
            g.DrawLine(gridPen, plot.Left, y, plot.Right, y);
            g.DrawString(((int)Math.Round(maxCount * i / 4.0)).ToString(CultureInfo.InvariantCulture), font, textBrush, 8, y - 8);
        }

        var gap = 3;
        var barWidth = Math.Max(1, (plot.Width - gap * (binCount - 1)) / binCount);
        for (var i = 0; i < binCount; i++)
        {
            var barHeight = (int)Math.Round((double)bins[i] / maxCount * plot.Height);
            var x = plot.Left + i * (barWidth + gap);
            var y = plot.Bottom - barHeight;
            g.FillRectangle(barBrush, x, y, barWidth, barHeight);
        }

        g.DrawRectangle(axisPen, plot);
        g.DrawString($"min {min:0.##}", font, textBrush, plot.Left, plot.Bottom + 8);
        g.DrawString($"max {values.Max():0.##}", font, textBrush, plot.Right - 80, plot.Bottom + 8);
        g.DrawString($"avg {average:0.##}", font, textBrush, plot.Left + plot.Width / 2 - 34, plot.Bottom + 8);
        return bitmap;
    }

    private void ExportCurrentTableCsv()
    {
        if (_currentTableResult == null) return;
        using var dialog = new SaveFileDialog
        {
            Title = "导出当前表为 CRS",
            Filter = "CSV 文件 (*.csv)|*.csv|所有文件 (*.*)|*.*",
            FileName = MakeSafeFileName(_currentTableResult.Table.TableName) + ".csv"
        };
        if (dialog.ShowDialog(this) != DialogResult.OK) return;

        try
        {
            CsvService.Export(_currentTableResult.Data, dialog.FileName);
            Log("已导出 CSV：" + dialog.FileName);
            SetStatus("CSV 导出完成");
        }
        catch (Exception ex)
        {
            Log("CSV 导出失败：" + ex);
            MessageBox.Show(this, ex.Message, "CSV 导出失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }

    private void ExportVisibleTableColumnsCsv()
    {
        if (_currentTableResult == null) return;

        _dataGrid.EndEdit();
        var visibleColumns = _dataGrid.Columns
            .Cast<DataGridViewColumn>()
            .Where(c => c.Visible && !string.IsNullOrWhiteSpace(c.DataPropertyName) && _currentTableResult.Data.Columns.Contains(c.DataPropertyName))
            .OrderBy(c => c.DisplayIndex)
            .Select(c => c.DataPropertyName)
            .Distinct(StringComparer.Ordinal)
            .ToList();
        var visibleRows = GetVisibleTableDataRowsFromGrid();
        if (visibleColumns.Count == 0)
        {
            MessageBox.Show(this, "当前没有可导出的可见列。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        if (visibleRows.Count == 0)
        {
            MessageBox.Show(this, "当前没有可导出的可见行。请清除行筛选或调整筛选条件。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        using var dialog = new SaveFileDialog
        {
            Title = "导出当前表可见列为 CRS",
            Filter = "CSV 文件 (*.csv)|*.csv|所有文件 (*.*)|*.*",
            FileName = MakeSafeFileName(_currentTableResult.Table.TableName) + "_可见列.csv"
        };
        if (dialog.ShowDialog(this) != DialogResult.OK) return;

        try
        {
            if (_visibleColumnsCsvWithNotes.Checked)
            {
                CsvService.ExportColumnsRowsWithAnnotationRow(_currentTableResult.Data, dialog.FileName, visibleColumns, BuildVisibleColumnCsvNotes(visibleColumns), visibleRows);
            }
            else
            {
                CsvService.ExportColumnsRows(_currentTableResult.Data, dialog.FileName, visibleColumns, visibleRows);
            }

            var noteText = _visibleColumnsCsvWithNotes.Checked ? "，含字段说明行" : string.Empty;
            Log($"已导出可见行列 CSV：{dialog.FileName}，行数 {visibleRows.Count}/{_currentTableResult.Data.Rows.Count}，列数 {visibleColumns.Count}/{_currentTableResult.Data.Columns.Count}{noteText}");
            SetStatus($"可见行列 CSV 导出完成：{visibleRows.Count} 行，{visibleColumns.Count} 列{noteText}");
        }
        catch (Exception ex)
        {
            Log("可见列 CSV 导出失败：" + ex);
            MessageBox.Show(this, ex.Message, "可见列 CSV 导出失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }

    private List<DataRow> GetVisibleTableDataRowsFromGrid()
    {
        var rows = new List<DataRow>();
        foreach (DataGridViewRow gridRow in _dataGrid.Rows)
        {
            if (!gridRow.Visible) continue;
            var row = TryGetDataRow(gridRow);
            if (row != null) rows.Add(row);
        }
        return rows;
    }

    private Dictionary<string, string> BuildVisibleColumnCsvNotes(IReadOnlyList<string> visibleColumns)
    {
        var notes = new Dictionary<string, string>(StringComparer.Ordinal);
        if (_currentTableResult == null) return notes;

        foreach (var columnName in visibleColumns)
        {
            if (columnName == "ID")
            {
                notes[columnName] = "行号/编号；用于回查原始数据，不直接写入二进制。";
                continue;
            }

            if (!_currentTableResult.Data.Columns.Contains(columnName) ||
                _currentTableResult.Data.Columns[columnName]!.ExtendedProperties["FieldDefinition"] is not HexFieldDefinition field)
            {
                notes[columnName] = string.Empty;
                continue;
            }

            var shortNote = _fieldAnnotationService.BuildShortFieldAnnotation(_currentTableResult.Table, field);
            var semantic = _fieldAnnotationService.GetSemanticShortName(_currentTableResult.Table, field);
            var risk = _fieldAnnotationService.GetRiskReason(_currentTableResult.Table, field);
            notes[columnName] = string.IsNullOrWhiteSpace(risk)
                ? $"{shortNote}；语义：{semantic}"
                : $"{shortNote}；语义：{semantic}；风险：{risk}";
        }

        return notes;
    }

    private static DataRow? TryGetDataRow(DataGridViewRow gridRow)
    {
        return gridRow.DataBoundItem switch
        {
            DataRowView rowView => rowView.Row,
            DataRow row => row,
            _ => null
        };
    }

    private static bool IsDataRowChanged(DataRow row)
        => row.RowState is not DataRowState.Unchanged and not DataRowState.Detached;

    private void RefreshDataGridRowStyles()
    {
        foreach (DataGridViewRow row in _dataGrid.Rows)
        {
            RefreshDataGridRowStyle(row.Index);
        }

        HighlightCurrentTableCellsWithCreatorNotes();
    }

    private void RefreshDataGridRowStyle(int rowIndex)
    {
        if (rowIndex < 0 || rowIndex >= _dataGrid.Rows.Count) return;
        var gridRow = _dataGrid.Rows[rowIndex];
        var dataRow = TryGetDataRow(gridRow);
        if (dataRow == null) return;

        if (IsDataRowChanged(dataRow))
        {
            gridRow.DefaultCellStyle.BackColor = Color.LightCyan;
            gridRow.DefaultCellStyle.SelectionBackColor = Color.Teal;
        }
        else
        {
            gridRow.DefaultCellStyle.BackColor = Color.Empty;
            gridRow.DefaultCellStyle.SelectionBackColor = Color.Empty;
        }
    }

    private void HighlightCurrentTableCellsWithCreatorNotes()
    {
        if (_currentTableResult == null || _dataGrid.Columns.Count == 0)
        {
            return;
        }

        foreach (DataGridViewRow gridRow in _dataGrid.Rows)
        {
            if (gridRow.IsNewRow) continue;

            var rowId = gridRow.Cells.Count > 0
                ? Convert.ToString(gridRow.Cells[0].Value, CultureInfo.InvariantCulture) ?? gridRow.Index.ToString(CultureInfo.InvariantCulture)
                : gridRow.Index.ToString(CultureInfo.InvariantCulture);
            var rowNoteCount = 0;

            foreach (DataGridViewCell cell in gridRow.Cells)
            {
                cell.Style.BackColor = Color.Empty;
                cell.Style.SelectionBackColor = Color.Empty;
                cell.ToolTipText = string.Empty;

                if (_currentCreatorNotes.Count == 0) continue;
                if (cell.ColumnIndex < 0 || cell.ColumnIndex >= _dataGrid.Columns.Count) continue;

                var propertyName = _dataGrid.Columns[cell.ColumnIndex].DataPropertyName;
                if (string.IsNullOrWhiteSpace(propertyName) || propertyName == "ID") continue;
                if (!_currentTableResult.Data.Columns.Contains(propertyName)) continue;

                var targetKey = BuildTableCellCreatorNoteTargetKey(_currentTableResult.Table.TableName, rowId, propertyName);
                var count = _creatorNoteRelationService.CountExact(_currentCreatorNotes, "数据表单元格", targetKey);
                if (count <= 0) continue;

                rowNoteCount += count;
                cell.Style.BackColor = BlendRowColor(gridRow.DefaultCellStyle.BackColor, Color.FromArgb(232, 245, 255));
                cell.Style.SelectionBackColor = Color.SteelBlue;
                cell.ToolTipText = BuildCreatorNoteTip(count);
            }

            if (rowNoteCount > 0)
            {
                gridRow.HeaderCell.Value = "注";
                gridRow.HeaderCell.ToolTipText = BuildCreatorNoteTip(rowNoteCount);
            }
            else if (Equals(gridRow.HeaderCell.Value, "注"))
            {
                gridRow.HeaderCell.Value = null;
                gridRow.HeaderCell.ToolTipText = string.Empty;
            }
        }
    }

