    private void SetCreatorNoteScope(string scope)
    {
        var index = _creatorNoteScopeCombo.Items.IndexOf(scope);
        if (index < 0)
        {
            _creatorNoteScopeCombo.Items.Add(scope);
            index = _creatorNoteScopeCombo.Items.Count - 1;
        }
        _creatorNoteScopeCombo.SelectedIndex = Math.Max(0, index);
    }

    private void LoadImageResources()
    {
        if (_project == null)
        {
            MessageBox.Show(this, "请先打开 MOD 项目目录。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        try
        {
            Cursor = Cursors.WaitCursor;
            _imageResourceCatalogService.ClearCache();
            _currentImageResourceFiles = _imageResourceCatalogService.BuildCatalog(_project);
            PopulateImageResourceCategoryFilter();
            BindImageResourceFiles(_currentImageResourceFiles);
            SetPictureBoxImage(_imageResourcePreviewBox, null);
            _imageResourceEntryInfoBox.Clear();
            var indexed = _currentImageResourceFiles.Count(x => x.SupportsE5Index);
            var replaceable = _currentImageResourceFiles.Count(x => x.CanReplace);
            var previewable = _currentImageResourceFiles.Count(x => x.SupportsPreview);
            _imageResourceInfoBox.Text =
                $"图片资源已读取：文件 {_currentImageResourceFiles.Count} 个，可预览 {previewable} 个，可读取 0x110 E5 图片索引 {indexed} 个，可单条替换 {replaceable} 个。\r\n" +
                "覆盖：角色头像、R/S形象、道具/策略图标、攻击/穿透范围、策略动画、Logo/Mmap/Tr/U_select/Gate/Weather 等图片资源；战场地图底图不在此模块。\r\n" +
                "别名兼容：efffare.e5 -> Effarea.e5；gete.e5 -> Gate.e5；warther.e5 -> Weather.e5。";
            Log($"已读取图片资源目录：{_currentImageResourceFiles.Count} 个文件。");
            SetStatus("图片资源读取完成");
        }
        catch (Exception ex)
        {
            _imageResourceInfoBox.Text = ex.ToString();
            Log("图片资源读取失败：" + ex);
            MessageBox.Show(this, ex.Message, "图片资源读取失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
        finally
        {
            Cursor = Cursors.Default;
        }
    }

    private void PopulateImageResourceCategoryFilter()
    {
        var previous = Convert.ToString(_imageResourceCategoryFilterCombo.SelectedItem, CultureInfo.InvariantCulture);
        _imageResourceCategoryFilterCombo.Items.Clear();
        _imageResourceCategoryFilterCombo.Items.Add("全部");
        foreach (var category in _currentImageResourceFiles.Select(x => x.Category).Distinct().OrderBy(x => x, StringComparer.CurrentCultureIgnoreCase))
        {
            _imageResourceCategoryFilterCombo.Items.Add(category);
        }

        SelectComboValueOrFirst(_imageResourceCategoryFilterCombo, previous);
    }

    private void ApplyImageResourceFilter()
    {
        if (_currentImageResourceFiles.Count == 0) return;
        var category = Convert.ToString(_imageResourceCategoryFilterCombo.SelectedItem, CultureInfo.InvariantCulture) ?? "全部";
        var keyword = _imageResourceSearchBox.Text.Trim();
        var filtered = _currentImageResourceFiles.Where(item =>
            (category == "全部" || item.Category.Equals(category, StringComparison.Ordinal)) &&
            (string.IsNullOrWhiteSpace(keyword) || ImageResourceFileMatchesKeyword(item, keyword)))
            .ToList();
        BindImageResourceFiles(filtered);
        SetStatus($"图片资源筛选：{filtered.Count}/{_currentImageResourceFiles.Count}");
    }

    private void ClearImageResourceFilter()
    {
        _imageResourceSearchBox.Clear();
        if (_imageResourceCategoryFilterCombo.Items.Count > 0) _imageResourceCategoryFilterCombo.SelectedIndex = 0;
        BindImageResourceFiles(_currentImageResourceFiles);
        SetStatus("已显示全部图片资源");
    }

    private static bool ImageResourceFileMatchesKeyword(ImageResourceFileInfo item, string keyword)
        => item.DisplayName.Contains(keyword, StringComparison.CurrentCultureIgnoreCase) ||
           item.FileName.Contains(keyword, StringComparison.CurrentCultureIgnoreCase) ||
           item.Aliases.Contains(keyword, StringComparison.CurrentCultureIgnoreCase) ||
           item.Usage.Contains(keyword, StringComparison.CurrentCultureIgnoreCase) ||
           item.Status.Contains(keyword, StringComparison.CurrentCultureIgnoreCase) ||
           item.KindSummary.Contains(keyword, StringComparison.CurrentCultureIgnoreCase);

    private void BindImageResourceFiles(IEnumerable<ImageResourceFileInfo> rows)
    {
        _imageResourceFileGrid.DataSource = new BindingList<ImageResourceFileInfo>(rows.ToList());
        ConfigureImageResourceFileGrid();
        _currentImageResourceEntries = Array.Empty<ImageResourceEntryInfo>();
        _imageResourceEntryGrid.DataSource = null;
        SetPictureBoxImage(_imageResourcePreviewBox, null);
        _imageResourceEntryInfoBox.Clear();
    }

    private void ConfigureImageResourceFileGrid()
    {
        foreach (DataGridViewColumn column in _imageResourceFileGrid.Columns)
        {
            column.ReadOnly = true;
            if (column.DataPropertyName is nameof(ImageResourceFileInfo.Path)
                or nameof(ImageResourceFileInfo.RelativePath)
                or nameof(ImageResourceFileInfo.SafetyNote)
                or nameof(ImageResourceFileInfo.Usage))
            {
                column.Visible = false;
            }

            column.HeaderText = column.DataPropertyName switch
            {
                nameof(ImageResourceFileInfo.Category) => "分类",
                nameof(ImageResourceFileInfo.DisplayName) => "资源",
                nameof(ImageResourceFileInfo.FileName) => "文件",
                nameof(ImageResourceFileInfo.Aliases) => "别名",
                nameof(ImageResourceFileInfo.Exists) => "存在",
                nameof(ImageResourceFileInfo.SizeBytes) => "大小",
                nameof(ImageResourceFileInfo.EntryCount) => "条目",
                nameof(ImageResourceFileInfo.SupportsE5Index) => "E5索引",
                nameof(ImageResourceFileInfo.SupportsPreview) => "可预览",
                nameof(ImageResourceFileInfo.CanReplace) => "可替换",
                nameof(ImageResourceFileInfo.ResourceFormat) => "类型",
                nameof(ImageResourceFileInfo.KindSummary) => "格式",
                nameof(ImageResourceFileInfo.Status) => "状态",
                _ => column.HeaderText
            };
        }
    }

    private void ConfigureImageResourceEntryGrid()
    {
        foreach (DataGridViewColumn column in _imageResourceEntryGrid.Columns)
        {
            column.ReadOnly = true;
            if (column.DataPropertyName is nameof(ImageResourceEntryInfo.Path)
                or nameof(ImageResourceEntryInfo.ResourceKey)
                or nameof(ImageResourceEntryInfo.Category)
                or nameof(ImageResourceEntryInfo.ResourceName)
                or nameof(ImageResourceEntryInfo.FileName)
                or nameof(ImageResourceEntryInfo.CanReplace))
            {
                column.Visible = false;
            }

            column.HeaderText = column.DataPropertyName switch
            {
                nameof(ImageResourceEntryInfo.ImageNumber) => "编号",
                nameof(ImageResourceEntryInfo.IndexOffset) => "索引偏移",
                nameof(ImageResourceEntryInfo.DataOffset) => "数据偏移",
                nameof(ImageResourceEntryInfo.StoredLength) => "存储",
                nameof(ImageResourceEntryInfo.DecodedLength) => "解码",
                nameof(ImageResourceEntryInfo.IsCompressed) => "压缩",
                nameof(ImageResourceEntryInfo.Kind) => "格式",
                nameof(ImageResourceEntryInfo.Usage) => "用途候选",
                _ => column.HeaderText
            };
        }
    }

    private ImageResourceFileInfo? GetSelectedImageResourceFile()
    {
        if (_imageResourceFileGrid.CurrentRow?.DataBoundItem is ImageResourceFileInfo current) return current;
        if (_imageResourceFileGrid.SelectedRows.Count > 0 && _imageResourceFileGrid.SelectedRows[0].DataBoundItem is ImageResourceFileInfo selected) return selected;
        return null;
    }

    private ImageResourceEntryInfo? GetSelectedImageResourceEntry()
    {
        if (_imageResourceEntryGrid.CurrentRow?.DataBoundItem is ImageResourceEntryInfo current) return current;
        if (_imageResourceEntryGrid.SelectedRows.Count > 0 && _imageResourceEntryGrid.SelectedRows[0].DataBoundItem is ImageResourceEntryInfo selected) return selected;
        return null;
    }

    private void ShowSelectedImageResourceFile()
    {
        if (_project == null) return;
        var item = GetSelectedImageResourceFile();
        if (item == null) return;

        _currentImageResourceEntries = _imageResourceCatalogService.ReadEntries(item);
        _imageResourceEntryGrid.DataSource = new BindingList<ImageResourceEntryInfo>(_currentImageResourceEntries.ToList());
        ConfigureImageResourceEntryGrid();
        SetPictureBoxImage(_imageResourcePreviewBox, null);
        _imageResourceInfoBox.Text =
            $"资源：{item.DisplayName}\r\n" +
            $"分类：{item.Category}    文件：{item.FileName}    别名：{(string.IsNullOrWhiteSpace(item.Aliases) ? "无" : item.Aliases)}\r\n" +
            $"用途：{item.Usage}\r\n" +
            $"状态：{item.Status}    条目：{item.EntryCount}    类型：{item.ResourceFormat}    格式：{(string.IsNullOrWhiteSpace(item.KindSummary) ? "未识别" : item.KindSummary)}\r\n" +
            $"路径：{item.Path}\r\n" +
            $"安全边界：{item.SafetyNote}";
        _imageResourceEntryInfoBox.Text = item.SupportsPreview
            ? item.SupportsE5Index
                ? "选择下方编号可预览；替换只更新选中的单个 0x110 E5 索引条目。"
                : "选择下方编号可预览；DLL 图标当前只读，不开放替换。"
            : "当前文件没有可读取/预览的图片条目，暂不开放条目替换。";
        SetStatus($"图片资源：{item.DisplayName}");
    }

    private void ShowSelectedImageResourceEntry()
    {
        if (_project == null) return;
        var entry = GetSelectedImageResourceEntry();
        if (entry == null) return;

        Bitmap? bitmap = null;
        try
        {
            bitmap = _imageResourceCatalogService.RenderEntryPreview(_project, entry);
        }
        catch (Exception ex)
        {
            Log("图片资源条目预览失败：" + ex);
        }

        SetPictureBoxImage(_imageResourcePreviewBox, bitmap);
        _imageResourceEntryInfoBox.Text = entry.Kind.Equals("DLL图标", StringComparison.OrdinalIgnoreCase)
            ? $"{entry.ResourceName}  编号 #{entry.ImageNumber}\r\n" +
              $"用途候选：{entry.Usage}\r\n" +
              $"来源：{entry.FileName}\r\n" +
              $"路径：{entry.Path}\r\n" +
              (bitmap == null
                  ? "预览：已生成编号条目，但 DLL 图标解析/渲染失败。"
                  : "预览：已复用宝物/策略图标预览服务按字段编号渲染。")
            : $"{entry.ResourceName}  图号 #{entry.ImageNumber}\r\n" +
              $"用途候选：{entry.Usage}\r\n" +
              $"索引偏移：0x{entry.IndexOffset:X}    数据偏移：0x{entry.DataOffset:X}\r\n" +
              $"大小：stored={entry.StoredLength:N0}    decoded={entry.DecodedLength:N0}    格式={entry.Kind}    压缩={entry.IsCompressed}\r\n" +
              $"路径：{entry.Path}\r\n" +
              (bitmap == null
                  ? "预览：条目存在，但不是当前可直接解码/渲染的 BMP/JPG/PNG/已知 RAW 帧。"
                  : "预览：已按 E5 条目内容渲染。");
        SetStatus($"图片条目：{entry.FileName} #{entry.ImageNumber}");
    }

    private void OpenSelectedImageResourceLocation()
    {
        var item = GetSelectedImageResourceFile();
        if (item == null)
        {
            MessageBox.Show(this, "请先选择一个图片资源文件。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        OpenFileLocation(File.Exists(item.Path) ? item.Path : Path.GetDirectoryName(item.Path) ?? item.Path);
    }

    private void ImportOrReplaceSelectedImageResourceEntry(bool restoreMode)
    {
        if (_project == null)
        {
            MessageBox.Show(this, "请先加载项目。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        var entry = GetSelectedImageResourceEntry();
        if (entry == null)
        {
            MessageBox.Show(this, "请先选择一个 E5 图片条目。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        if (!entry.CanReplace)
        {
            MessageBox.Show(this, "当前资源不开放直接替换。请先确认该资源的写回规则。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        var target = new E5ImageReplacementTarget(
            1,
            entry.Category,
            $"{entry.ResourceName} #{entry.ImageNumber}",
            entry.Path,
            entry.ImageNumber,
            entry.IndexOffset,
            entry.DataOffset,
            entry.StoredLength,
            entry.Kind,
            entry.Usage);

        string sourcePath;
        E5ImageReplacePreviewResult preview;
        if (restoreMode)
        {
            var backupRoot = Path.Combine(_project.GameRoot, "_CCZModStudio_Backups");
            using var dialog = new OpenFileDialog
            {
                Title = $"选择包含图 #{entry.ImageNumber} 的备份 E5 文件",
                InitialDirectory = Directory.Exists(backupRoot) ? backupRoot : _project.GameRoot,
                Filter = "E5 文件 (*.e5)|*.e5|所有文件 (*.*)|*.*",
                CheckFileExists = true
            };
            if (dialog.ShowDialog(this) != DialogResult.OK) return;
            sourcePath = dialog.FileName;

            try
            {
                Cursor = Cursors.WaitCursor;
                preview = _e5ImageReplaceService.PreviewReplacementFromEntry(_project, entry.Path, entry.ImageNumber, sourcePath);
            }
            catch (Exception ex)
            {
                Log("图片资源 E5 还原预览失败：" + ex);
                MessageBox.Show(this, ex.Message, "E5 还原预览失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
                return;
            }
            finally
            {
                Cursor = Cursors.Default;
            }
        }
        else
        {
            using var dialog = new OpenFileDialog
            {
                Title = $"选择导入到 {entry.FileName} 图 #{entry.ImageNumber} 的图片",
                Filter = "图片条目 (*.bmp;*.jpg;*.jpeg;*.png)|*.bmp;*.jpg;*.jpeg;*.png|所有文件 (*.*)|*.*",
                CheckFileExists = true
            };
            if (dialog.ShowDialog(this) != DialogResult.OK) return;
            sourcePath = dialog.FileName;

            try
            {
                Cursor = Cursors.WaitCursor;
                preview = _e5ImageReplaceService.PreviewReplacement(_project, entry.Path, entry.ImageNumber, sourcePath);
            }
            catch (Exception ex)
            {
                Log("图片资源 E5 替换预览失败：" + ex);
                MessageBox.Show(this, ex.Message, "E5 替换预览失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
                return;
            }
            finally
            {
                Cursor = Cursors.Default;
            }
        }

        var previewText = BuildE5ImageReplacePreviewText(target, preview, restoreMode);
        _imageResourceEntryInfoBox.Text = previewText;
        if (MessageBox.Show(this,
                previewText + "\r\n\r\n确认后会先备份目标 E5 文件，再写入该单个图片条目。是否继续？",
                restoreMode ? "确认还原 E5 图片条目" : "确认替换 E5 图片条目",
                MessageBoxButtons.YesNo,
                MessageBoxIcon.Question) != DialogResult.Yes)
        {
            return;
        }

        try
        {
            Cursor = Cursors.WaitCursor;
            var result = restoreMode
                ? _e5ImageReplaceService.ReplaceFromEntry(_project, entry.Path, entry.ImageNumber, sourcePath)
                : _e5ImageReplaceService.Replace(_project, entry.Path, entry.ImageNumber, sourcePath);
            _imageResourceCatalogService.ClearCache();
            LoadImageResources();
            _imageResourceEntryInfoBox.Text = BuildE5ImageReplaceResultText(result);
            Log($"图片资源 E5 条目{(restoreMode ? "还原" : "替换")}完成：{result.TargetRelativePath} #{result.ImageNumber}");
            SetStatus(restoreMode ? "图片资源 E5 条目还原完成" : "图片资源 E5 条目替换完成");
        }
        catch (Exception ex)
        {
            Log("图片资源 E5 条目写入失败：" + ex);
            MessageBox.Show(this, ex.Message, restoreMode ? "E5 还原失败" : "E5 替换失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
        finally
        {
            Cursor = Cursors.Default;
        }
    }

    private void ExportImageResourceEntriesCsv()
    {
        if (_currentImageResourceEntries.Count == 0)
        {
            MessageBox.Show(this, "当前没有可导出的图片条目。请先读取图片资源并选择一个 E5 文件。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        ExportGridItemsCsv<ImageResourceEntryInfo>(_imageResourceEntryGrid, "导出图片资源条目", "图片资源E5条目.csv", "ImageResourceEntries", "图片资源E5条目");
    }

    private void LoadImageAssignments()
    {
        if (_project == null || _tables.Count == 0)
        {
            MessageBox.Show(this, "请先加载项目和表定义。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        try
        {
            Cursor = Cursors.WaitCursor;
            _currentImageAssignments = _imageAssignmentService.Load(_project, _tables);
            _imageAssignmentSearchBox.Clear();
            _imageAssignmentMissingOnlyCheckBox.Checked = false;
            _imageAssignmentGrid.DataSource = _currentImageAssignments;
            _clearImageAssignmentFilterButton.Enabled = false;
            var canEdit = true;
            _imageAssignmentGrid.ReadOnly = !canEdit;
            _saveImageAssignmentsButton.Enabled = canEdit;
            foreach (DataGridViewColumn column in _imageAssignmentGrid.Columns)
            {
                column.ReadOnly = !canEdit || column.DataPropertyName is "ID" or "名称" or "头像编号" or "职业" or "职业名称" or "R资源状态" or "S资源状态";
                if (column.DataPropertyName == "头像编号")
                {
                    column.Width = 76;
                    column.ToolTipText = "来自人物表“头像”字段；右侧会尝试从 E5\\Face.e5 抽取对应 PNG 头像作为人物确认预览。";
                }
                if (column.DataPropertyName == "职业")
                {
                    column.Width = 60;
                    column.ToolTipText = "来自人物表“职业”字段；S=0 默认兵种预览会用 职业*3+阵营槽 计算 Unit 图号。";
                }
                if (column.DataPropertyName == "职业名称")
                {
                    column.Width = 110;
                    column.ToolTipText = "根据 6.5-4 详细兵种自动引用的职业名称。";
                }
                if (column.DataPropertyName is "R资源状态" or "S资源状态")
                {
                    column.Width = 150;
                    column.ToolTipText = "R：根据 Pmapobj.e5 正/反图号解释编号；S：按紧凑编号映射到 Unit_atk/mov/spc.e5。预览按 E5 0x110 索引表取图。";
                }
            }
            ColorImageAssignmentResourceRows();
            var missingR = _currentImageAssignments.AsEnumerable().Count(row => CharacterImageResourceService.IsMissingStatus(Convert.ToString(row["R资源状态"], CultureInfo.InvariantCulture) ?? string.Empty));
            var missingS = _currentImageAssignments.AsEnumerable().Count(row => CharacterImageResourceService.IsMissingStatus(Convert.ToString(row["S资源状态"], CultureInfo.InvariantCulture) ?? string.Empty));
            _imageAssignmentSummaryText =
                $"已读取人物 R/S 形象联动表：{_currentImageAssignments.Rows.Count} 行。\r\n" +
                $"资源解释检查：R 未定位 {missingR} 项，S 未/部分定位 {missingS} 项。\r\n" +
                "右侧显示人物表头像预览，并按 E5 0x110 索引表显示 R/S 形象预览：R=n 取 Pmapobj.e5 图 2n+1；S=0 按职业和预览阵营取默认兵种图，S=1..32 取三转特殊三张图，S>=33 取一转特殊单张图。当前项目可直接编辑 R形象编号 / S形象编号，保存时会写入 Ekd5.exe，保存前自动备份，保存后复读校验。";
            _imageAssignmentInfoBox.Text = _imageAssignmentSummaryText;
            ShowSelectedImageAssignmentDetail();
            Log("已读取人物 R/S 形象联动表。");
            SetStatus("人物 R/S 形象读取完成");
        }
        catch (Exception ex)
        {
            _imageAssignmentInfoBox.Text = ex.ToString();
            Log("读取人物 R/S 形象失败：" + ex);
            MessageBox.Show(this, ex.Message, "读取人物 R/S 形象失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
        finally
        {
            Cursor = Cursors.Default;
        }
    }

    private void ApplyImageAssignmentFilter()
    {
        if (_currentImageAssignments == null)
        {
            return;
        }

        var keyword = _imageAssignmentSearchBox.Text.Trim();
        var missingOnly = _imageAssignmentMissingOnlyCheckBox.Checked;
        if (string.IsNullOrWhiteSpace(keyword) && !missingOnly)
        {
            _currentImageAssignments.DefaultView.RowFilter = string.Empty;
            _clearImageAssignmentFilterButton.Enabled = false;
            ColorImageAssignmentResourceRows();
            ShowSelectedImageAssignmentDetail();
            SetStatus("人物 R/S 筛选已清除");
            return;
        }

        var filters = new List<string>();
        if (missingOnly)
        {
            filters.Add("([R资源状态] LIKE '缺失*' OR [S资源状态] LIKE '缺失*')");
        }

        if (!string.IsNullOrWhiteSpace(keyword))
        {
            var escaped = EscapeDataViewLikeValue(keyword);
            var searchableColumns = new[] { "ID", "名称", "头像编号", "职业", "职业名称", "R形象编号", "S形象编号", "R资源状态", "S资源状态" }
                .Where(name => _currentImageAssignments.Columns.Contains(name))
                .Select(name => $"CONVERT([{name}], 'System.String') LIKE '*{escaped}*'")
                .ToList();
            if (searchableColumns.Count > 0)
            {
                filters.Add("(" + string.Join(" OR ", searchableColumns) + ")");
            }
        }

        _currentImageAssignments.DefaultView.RowFilter = string.Join(" AND ", filters);
        _clearImageAssignmentFilterButton.Enabled = true;
        ColorImageAssignmentResourceRows();
        ShowSelectedImageAssignmentDetail();
        SetStatus($"人物 R/S 筛选：显示 {_currentImageAssignments.DefaultView.Count}/{_currentImageAssignments.Rows.Count} 行");
    }

    private void ClearImageAssignmentFilter()
    {
        _imageAssignmentSearchBox.Clear();
        if (_imageAssignmentMissingOnlyCheckBox.Checked)
        {
            _imageAssignmentMissingOnlyCheckBox.Checked = false;
        }

        if (_currentImageAssignments != null)
        {
            _currentImageAssignments.DefaultView.RowFilter = string.Empty;
        }

        _clearImageAssignmentFilterButton.Enabled = false;
        ColorImageAssignmentResourceRows();
        ShowSelectedImageAssignmentDetail();
        SetStatus("人物 R/S 筛选已清除，已显示全部人物。");
    }

    private void UpdateImageAssignmentResourceStatus(int rowIndex)
    {
        if (_project == null || _currentImageAssignments == null || rowIndex < 0 || rowIndex >= _imageAssignmentGrid.Rows.Count) return;
        if (_imageAssignmentGrid.Rows[rowIndex].DataBoundItem is not DataRowView rowView) return;
        var row = rowView.Row;
        if (!_currentImageAssignments.Columns.Contains("R资源状态") || !_currentImageAssignments.Columns.Contains("S资源状态")) return;

        var r = Convert.ToInt32(row["R形象编号"], CultureInfo.InvariantCulture);
        var s = Convert.ToInt32(row["S形象编号"], CultureInfo.InvariantCulture);
        row["R资源状态"] = ImageAssignmentService.GetImageResourceStatus(_project, "R", r);
        row["S资源状态"] = ImageAssignmentService.GetImageResourceStatus(_project, "S", s);
        ColorImageAssignmentResourceRow(_imageAssignmentGrid.Rows[rowIndex]);
        SetStatus($"资源检查：R={row["R资源状态"]}，S={row["S资源状态"]}");
        ShowSelectedImageAssignmentDetail();
    }

    private void ColorImageAssignmentResourceRows()
    {
        foreach (DataGridViewRow row in _imageAssignmentGrid.Rows)
        {
            ColorImageAssignmentResourceRow(row);
        }
    }

    private static void ColorImageAssignmentResourceRow(DataGridViewRow gridRow)
    {
        if (gridRow.DataBoundItem is not DataRowView rowView) return;
        var rStatus = Convert.ToString(rowView.Row["R资源状态"], CultureInfo.InvariantCulture) ?? string.Empty;
        var sStatus = Convert.ToString(rowView.Row["S资源状态"], CultureInfo.InvariantCulture) ?? string.Empty;
        gridRow.DefaultCellStyle.BackColor =
            rStatus.StartsWith("缺失", StringComparison.Ordinal) || sStatus.StartsWith("缺失", StringComparison.Ordinal)
                ? Color.MistyRose
                : Color.Empty;
    }

    private void OpenRsDirectory()
    {
        if (_project == null)
        {
            MessageBox.Show(this, "\u8bf7\u5148\u52a0\u8f7d\u9879\u76ee\u3002", "\u63d0\u793a", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        var rsDir = Path.Combine(_project.GameRoot, "RS");
        if (!Directory.Exists(rsDir))
        {
            MessageBox.Show(this, "\u627e\u4e0d\u5230 RS \u76ee\u5f55\uff1a" + rsDir, "\u63d0\u793a", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        try
        {
            Process.Start(new ProcessStartInfo
            {
                FileName = rsDir,
                UseShellExecute = true
            });
            Log("\u5df2\u6253\u5f00 RS \u76ee\u5f55\uff1a" + rsDir);
        }
        catch (Exception ex)
        {
            Log("\u6253\u5f00 RS \u76ee\u5f55\u5931\u8d25\uff1a" + ex);
            MessageBox.Show(this, ex.Message, "\u6253\u5f00 RS \u76ee\u5f55\u5931\u8d25", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }

    private void ShowSelectedImageAssignmentDetail()
    {
        if (_currentImageAssignments == null || _project == null)
        {
            _imageAssignmentInfoBox.Text = _imageAssignmentSummaryText;
            ClearImageAssignmentPreview();
            return;
        }

        var row = GetSelectedImageAssignmentRow();
        if (row == null)
        {
            _imageAssignmentInfoBox.Text = _imageAssignmentSummaryText;
            ClearImageAssignmentPreview();
            return;
        }

        var id = Convert.ToString(row["ID"], CultureInfo.InvariantCulture) ?? string.Empty;
        var name = Convert.ToString(row["\u540d\u79f0"], CultureInfo.InvariantCulture) ?? string.Empty;
        var faceId = row.Table.Columns.Contains("头像编号") ? Convert.ToInt32(row["头像编号"], CultureInfo.InvariantCulture) : (int?)null;
        var jobId = row.Table.Columns.Contains("职业") ? Convert.ToInt32(row["职业"], CultureInfo.InvariantCulture) : (int?)null;
        var jobName = row.Table.Columns.Contains("职业名称") ? Convert.ToString(row["职业名称"], CultureInfo.InvariantCulture) ?? string.Empty : string.Empty;
        TryGetImageResourceId(row, "R", out var rId);
        TryGetImageResourceId(row, "S", out var sId);
        var sFactionSlot = GetImageAssignmentSPreviewFactionSlot();
        var sMapping = CharacterImageResourceService.ResolveSUnitImageMapping(sId, jobId, sFactionSlot);
        var rPath = ImageAssignmentService.GetImageResourcePath(_project, "R", rId);
        var sPath = ImageAssignmentService.GetImageResourcePath(_project, "S", sId);
        var rStatus = Convert.ToString(row["R\u8d44\u6e90\u72b6\u6001"], CultureInfo.InvariantCulture) ?? string.Empty;
        var sStatus = Convert.ToString(row["S\u8d44\u6e90\u72b6\u6001"], CultureInfo.InvariantCulture) ?? string.Empty;
        var detail =
            $"\u5f53\u524d\u9009\u4e2d\uff1aID={id}  \u540d\u79f0={name}\r\n" +
            $"头像={faceId?.ToString(CultureInfo.InvariantCulture) ?? "未读取"}  来源：人物表“头像”字段，预览来自 E5\\Face.e5\r\n" +
            $"职业={jobId?.ToString(CultureInfo.InvariantCulture) ?? "未读取"} {jobName}  S预览阵营={CharacterImageResourceService.BuildSPreviewFactionText(sFactionSlot)}\r\n" +
            $"R={rId:00}  {rStatus}  \u8def\u5f84\uff1a{rPath}\r\n" +
            $"S={sId:00}  {sStatus}  \u8def\u5f84\uff1a{sPath}\r\n" +
            $"S图号映射：{sMapping.Detail}\r\n" +
            "R/S 实图预览：按 E5 0x110 索引表取图；R=n -> Pmapobj.e5 图 2n+1；S 按默认兵种/三转特殊/一转特殊紧凑映射取 Unit 图。裸扫图片不会再显示。\r\n" +
            "\u63d0\u793a\uff1a\u5f53\u524d\u5355\u5143\u683c\u5728 S \u5217\u65f6\uff0c\u201c\u5b9a\u4f4d\u9009\u4e2d\u8d44\u6e90\u201d\u4f1a\u5b9a\u4f4d S\uff1b\u5176\u4ed6\u5217\u9ed8\u8ba4\u5b9a\u4f4d R\u3002";

        _imageAssignmentInfoBox.Text = string.IsNullOrWhiteSpace(_imageAssignmentSummaryText)
            ? detail
            : _imageAssignmentSummaryText + "\r\n\r\n" + detail;
        RefreshSelectedImageAssignmentPreview(name, rId, sId, faceId, jobId, sFactionSlot);
    }

    private void RefreshSelectedImageAssignmentPreview(string personName, int rId, int sId, int? faceId, int? jobId, int sFactionSlot)
    {
        if (_project == null)
        {
            ClearImageAssignmentPreview();
            return;
        }

        try
        {
            // R/S preview uses the E5 image index at 0x110; do not fall back to raw magic-order scans.
            SetPictureBoxImage(_imageAssignmentFacePreviewBox,
                faceId.HasValue ? _imageAssignmentPreviewService.TryRenderFaceImage(_project, faceId.Value) : null);
            SetPictureBoxImage(_imageAssignmentRPreviewBox, _imageAssignmentPreviewService.TryRenderCharacterResourceImage(_project, "R", rId));
            SetPictureBoxImage(_imageAssignmentSPreviewBox, _imageAssignmentPreviewService.TryRenderCharacterResourceImage(_project, "S", sId, jobId, sFactionSlot));
        }
        catch (Exception ex)
        {
            ClearImageAssignmentPreview();
            Log("ImageAssignment preview failed: " + ex);
        }
    }

    private void ClearImageAssignmentPreview()
    {
        SetPictureBoxImage(_imageAssignmentFacePreviewBox, null);
        SetPictureBoxImage(_imageAssignmentRPreviewBox, null);
        SetPictureBoxImage(_imageAssignmentSPreviewBox, null);
    }

    private int GetImageAssignmentSPreviewFactionSlot()
    {
        var selected = _imageAssignmentSPreviewFactionCombo.SelectedIndex + 1;
        return CharacterImageResourceService.NormalizeSPreviewFactionSlot(selected);
    }

    private string BuildCompactImageAssignmentInfo(string prefix, int id)
    {
        if (_project == null) return string.Empty;
        prefix = prefix.Equals("S", StringComparison.OrdinalIgnoreCase) ? "S" : "R";
        var resolver = new CharacterImageResourceService();
        var status = prefix == "S" ? resolver.BuildSStatus(_project, id) : resolver.BuildRStatus(_project, id);
        var fileText = File.Exists(status.Path) ? "已找到" : "未找到";
        return $"{prefix}={id:00}  {status.Status}  {status.ResourceName}\r\n{fileText}：{status.Path}\r\n{status.Detail}";
    }

    private static void SetPictureBoxImage(PictureBox box, Image? image)
    {
        var old = box.Image;
        box.Image = image;
        old?.Dispose();
    }

    private void LocateSelectedImageResource()
    {
        if (_project == null)
        {
            MessageBox.Show(this, "\u8bf7\u5148\u52a0\u8f7d\u9879\u76ee\u3002", "\u63d0\u793a", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        var row = GetSelectedImageAssignmentRow();
        if (row == null)
        {
            MessageBox.Show(this, "\u8bf7\u5148\u5728\u4eba\u7269 R/S \u9875\u9009\u62e9\u4e00\u884c\u3002", "\u63d0\u793a", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        var prefix = GetPreferredImageResourcePrefix();
        if (!TryGetImageResourceId(row, prefix, out var id))
        {
            MessageBox.Show(this, $"\u65e0\u6cd5\u8bfb\u53d6 {prefix} \u5f62\u8c61\u7f16\u53f7\u3002", "\u63d0\u793a", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        var path = ImageAssignmentService.GetImageResourcePath(_project, prefix, id);
        if (File.Exists(path))
        {
            OpenFileLocation(path);
            SetStatus($"\u5df2\u5b9a\u4f4d {prefix} \u8d44\u6e90\uff1a{Path.GetFileName(path)}");
            return;
        }

        OpenFileLocation(_project.GameRoot);
        MessageBox.Show(this,
            $"当前选中的 {prefix} 形象资源未定位：{Path.GetFileName(path)}\r\n已为你打开项目根目录。R 形象请检查 Pmapobj.e5；S 形象请检查 Unit_atk.e5 / Unit_mov.e5 / Unit_spc.e5。",
            "资源未定位",
            MessageBoxButtons.OK,
            MessageBoxIcon.Warning);
    }

    private void ImportOrReplaceSelectedImageResource(bool restoreMode)
    {
        if (_project == null)
        {
            MessageBox.Show(this, "请先加载项目。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        var row = GetSelectedImageAssignmentRow();
        if (row == null)
        {
            MessageBox.Show(this, "请先在人物 R/S 页面选择一行。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        var prefix = GetPreferredImageResourcePrefix();
        if (!TryGetImageResourceId(row, prefix, out var id))
        {
            MessageBox.Show(this, $"无法读取 {prefix} 形象编号。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        var targets = BuildE5ImageReplacementTargets(row, prefix, id);
        if (targets.Count == 0)
        {
            MessageBox.Show(this,
                $"当前 {prefix}={id} 没有可替换的有效 E5 图片条目。\r\n请确认 Pmapobj.e5 / Unit_*.e5 已存在，且映射图号没有超过索引表条目数。",
                "没有可替换条目",
                MessageBoxButtons.OK,
                MessageBoxIcon.Warning);
            return;
        }

        var target = SelectE5ImageReplacementTarget(targets, restoreMode);
        if (target == null) return;

        string sourcePath;
        E5ImageReplacePreviewResult preview;
        if (restoreMode)
        {
            var backupRoot = Path.Combine(_project.GameRoot, "_CCZModStudio_Backups");
            using var dialog = new OpenFileDialog
            {
                Title = $"选择包含图 #{target.ImageNumber} 的备份 E5 文件",
                InitialDirectory = Directory.Exists(backupRoot) ? backupRoot : _project.GameRoot,
                Filter = "E5 文件 (*.e5)|*.e5|所有文件 (*.*)|*.*",
                CheckFileExists = true
            };
            if (dialog.ShowDialog(this) != DialogResult.OK) return;
            sourcePath = dialog.FileName;

            try
            {
                Cursor = Cursors.WaitCursor;
                preview = _e5ImageReplaceService.PreviewReplacementFromEntry(_project, target.FilePath, target.ImageNumber, sourcePath);
            }
            catch (Exception ex)
            {
                Log("E5 条目还原预览失败：" + ex);
                MessageBox.Show(this, ex.Message, "E5 还原预览失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
                return;
            }
            finally
            {
                Cursor = Cursors.Default;
            }
        }
        else
        {
            using var dialog = new OpenFileDialog
            {
                Title = $"选择导入到 {Path.GetFileName(target.FilePath)} 图 #{target.ImageNumber} 的图片",
                Filter = "图片条目 (*.bmp;*.jpg;*.jpeg;*.png)|*.bmp;*.jpg;*.jpeg;*.png|所有文件 (*.*)|*.*",
                CheckFileExists = true
            };
            if (dialog.ShowDialog(this) != DialogResult.OK) return;
            sourcePath = dialog.FileName;

            try
            {
                Cursor = Cursors.WaitCursor;
                preview = _e5ImageReplaceService.PreviewReplacement(_project, target.FilePath, target.ImageNumber, sourcePath);
            }
            catch (Exception ex)
            {
                Log("E5 条目替换预览失败：" + ex);
                MessageBox.Show(this, ex.Message, "E5 替换预览失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
                return;
            }
            finally
            {
                Cursor = Cursors.Default;
            }
        }

        var previewText = BuildE5ImageReplacePreviewText(target, preview, restoreMode);
        _imageAssignmentInfoBox.Text = previewText;
        Log($"E5 条目{(restoreMode ? "还原" : "替换")}预览：{preview.TargetRelativePath} #{preview.ImageNumber} <- {preview.SourcePath}");

        if (MessageBox.Show(this,
                previewText + "\r\n\r\n确认后会先备份目标 E5 文件，再写入该单个图片条目。是否继续？",
                restoreMode ? "确认还原 E5 图片条目" : "确认替换 E5 图片条目",
                MessageBoxButtons.YesNo,
                MessageBoxIcon.Question) != DialogResult.Yes)
        {
            return;
        }

        try
        {
            Cursor = Cursors.WaitCursor;
            var result = restoreMode
                ? _e5ImageReplaceService.ReplaceFromEntry(_project, target.FilePath, target.ImageNumber, sourcePath)
                : _e5ImageReplaceService.Replace(_project, target.FilePath, target.ImageNumber, sourcePath);
            _imageAssignmentPreviewService.ClearCache();
            ShowSelectedImageAssignmentDetail();
            _imageAssignmentInfoBox.AppendText("\r\n\r\n" + BuildE5ImageReplaceResultText(result));
            Log($"E5 条目{(restoreMode ? "还原" : "替换")}完成：{result.TargetRelativePath} #{result.ImageNumber}，备份 {result.BackupPath}，结构化报告 {result.ReportJsonPath}");
            SetStatus(restoreMode ? "E5 图片条目还原完成" : "E5 图片条目替换完成");
        }
        catch (Exception ex)
        {
            Log("E5 条目写入失败：" + ex);
            MessageBox.Show(this, ex.Message, restoreMode ? "E5 还原失败" : "E5 替换失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
        finally
        {
            Cursor = Cursors.Default;
        }
    }

    private IReadOnlyList<E5ImageReplacementTarget> BuildE5ImageReplacementTargets(DataRow row, string prefix, int id)
    {
        if (_project == null) return Array.Empty<E5ImageReplacementTarget>();
        var result = new List<E5ImageReplacementTarget>();

        if (prefix == "R")
        {
            if (id < 0) return result;
            var path = CharacterImageResourceService.ResolveGameFile(_project, "Pmapobj.e5");
            AddE5ImageReplacementTarget(result, "R正面", "R", path, checked(id * 2 + 1), $"R={id} 正面图");
            AddE5ImageReplacementTarget(result, "R反面", "R", path, checked(id * 2 + 2), $"R={id} 反面图");
            return result;
        }

        var jobId = row.Table.Columns.Contains("职业") ? Convert.ToInt32(row["职业"], CultureInfo.InvariantCulture) : (int?)null;
        var sFactionSlot = GetImageAssignmentSPreviewFactionSlot();
        var mapping = CharacterImageResourceService.ResolveSUnitImageMapping(id, jobId, sFactionSlot);
        var unitFiles = new[]
        {
            ("移动", "Unit_mov.e5"),
            ("攻击", "Unit_atk.e5"),
            ("特技", "Unit_spc.e5")
        };

        foreach (var imageNumber in mapping.ImageNumbers)
        {
            foreach (var (action, fileName) in unitFiles)
            {
                var path = CharacterImageResourceService.ResolveGameFile(_project, fileName);
                AddE5ImageReplacementTarget(result, $"{action}#{imageNumber}", "S", path, imageNumber, $"S={id} -> Unit 图 #{imageNumber} {action}");
            }
        }

        return result;
    }

    private void AddE5ImageReplacementTarget(List<E5ImageReplacementTarget> result, string label, string prefix, string path, int imageNumber, string detail)
    {
        if (!File.Exists(path)) return;
        var entries = _e5ImageReplaceService.ReadIndex(path);
        if (imageNumber <= 0 || imageNumber > entries.Count) return;
        var entry = entries[imageNumber - 1];
        var sizeText = entry.IsCompressed
            ? $"stored={entry.StoredLength:N0} / decoded={entry.DecodedLength:N0}"
            : $"size={entry.Length:N0}";
        result.Add(new E5ImageReplacementTarget(
            result.Count + 1,
            prefix,
            label,
            path,
            imageNumber,
            entry.IndexOffset,
            entry.DataOffset,
            entry.Length,
            entry.Kind,
            $"{detail}；index=0x{entry.IndexOffset:X}；offset=0x{entry.DataOffset:X}；{sizeText}；kind={entry.Kind}"));
    }

    private E5ImageReplacementTarget? SelectE5ImageReplacementTarget(IReadOnlyList<E5ImageReplacementTarget> targets, bool restoreMode)
    {
        if (targets.Count == 1) return targets[0];

        using var dialog = new Form
        {
            Text = restoreMode ? "选择要还原的 E5 图片条目" : "选择要替换的 E5 图片条目",
            StartPosition = FormStartPosition.CenterParent,
            MinimizeBox = false,
            MaximizeBox = true,
            ShowInTaskbar = false
        };
        ApplyAdaptiveDialogSizing(dialog, new Size(980, 520), new Size(760, 420));

        var layout = new TableLayoutPanel
        {
            Dock = DockStyle.Fill,
            RowCount = 3,
            ColumnCount = 1,
            Padding = new Padding(10)
        };
        layout.RowStyles.Add(new RowStyle(SizeType.AutoSize));
        layout.RowStyles.Add(new RowStyle(SizeType.Percent, 100));
        layout.RowStyles.Add(new RowStyle(SizeType.AutoSize));
        dialog.Controls.Add(layout);

        layout.Controls.Add(new Label
        {
            Text = "请选择一个具体 E5 文件和图号。工具只会替换这一条索引，不会自动猜测其它动作帧。",
            AutoSize = true,
            Padding = new Padding(0, 0, 0, 8)
        }, 0, 0);

        var table = new DataTable();
        table.Columns.Add("序号", typeof(int));
        table.Columns.Add("条目", typeof(string));
        table.Columns.Add("E5文件", typeof(string));
        table.Columns.Add("图号", typeof(int));
        table.Columns.Add("格式", typeof(string));
        table.Columns.Add("大小", typeof(int));
        table.Columns.Add("说明", typeof(string));
        foreach (var target in targets)
        {
            table.Rows.Add(target.Index, target.Label, Path.GetFileName(target.FilePath), target.ImageNumber, target.Kind, target.OldSizeBytes, target.Detail);
        }

        var grid = new DataGridView
        {
            Dock = DockStyle.Fill,
            ReadOnly = true,
            AllowUserToAddRows = false,
            AllowUserToDeleteRows = false,
            SelectionMode = DataGridViewSelectionMode.FullRowSelect,
            AutoSizeColumnsMode = DataGridViewAutoSizeColumnsMode.Fill,
            DataSource = table
        };
        layout.Controls.Add(grid, 0, 1);

        var buttons = new FlowLayoutPanel
        {
            Dock = DockStyle.Fill,
            AutoSize = true,
            FlowDirection = FlowDirection.RightToLeft,
            Padding = new Padding(0, 8, 0, 0)
        };
        var okButton = new Button { Text = "选择", DialogResult = DialogResult.OK, AutoSize = true, MinimumSize = new Size(96, 32) };
        var cancelButton = new Button { Text = "取消", DialogResult = DialogResult.Cancel, AutoSize = true, MinimumSize = new Size(96, 32) };
        buttons.Controls.Add(okButton);
        buttons.Controls.Add(cancelButton);
        layout.Controls.Add(buttons, 0, 2);
        dialog.AcceptButton = okButton;
        dialog.CancelButton = cancelButton;

        if (grid.Rows.Count > 0)
        {
            grid.Rows[0].Selected = true;
            grid.CurrentCell = grid.Rows[0].Cells[0];
        }

        if (dialog.ShowDialog(this) != DialogResult.OK) return null;
        if (grid.CurrentRow == null) return null;
        var selectedTargetIndex = Convert.ToInt32(grid.CurrentRow.Cells["序号"].Value, CultureInfo.InvariantCulture);
        return targets.FirstOrDefault(target => target.Index == selectedTargetIndex);
    }

    private static string BuildE5ImageReplacePreviewText(E5ImageReplacementTarget target, E5ImageReplacePreviewResult preview, bool restoreMode)
    {
        var sourceSize = preview.SourceWidth.HasValue ? $"{preview.SourceWidth}x{preview.SourceHeight}" : "原始帧条/未知尺寸";
        return
            $"E5 图片条目{(restoreMode ? "还原" : "替换")}预览：{target.Label}\r\n" +
            $"目标：{preview.TargetRelativePath}    图号：#{preview.ImageNumber}\r\n" +
            $"来源：{preview.SourcePath}\r\n" +
            $"索引偏移：0x{preview.IndexOffset:X}    数据偏移：0x{preview.OldDataOffset:X} -> 0x{preview.NewDataOffset:X}\r\n" +
            $"条目大小：{preview.OldSizeBytes:N0} -> {preview.NewSizeBytes:N0} 字节    格式：{preview.OldKind} -> {preview.NewKind}    来源尺寸：{sourceSize}\r\n" +
            $"文件大小：{preview.OldFileSizeBytes:N0} -> {preview.NewFileSizeBytes:N0} 字节（{FormatSignedBytes(preview.FileSizeDeltaBytes)}）\r\n" +
            $"写入方式：{preview.Placement}    改动估算：{preview.ChangedBytesEstimate:N0} 字节\r\n" +
            $"SHA256：{ShortSha256(preview.OldFileSha256)} -> {ShortSha256(preview.NewFileSha256)}    来源：{ShortSha256(preview.SourceSha256)}\r\n" +
            $"格式提示：{(preview.FormatWarnings.Count == 0 ? "无" : string.Join("；", preview.FormatWarnings))}\r\n" +
            $"风险提示：{preview.RiskSummary}\r\n" +
            "说明：只更新 0x110 索引表中的指定图号，不重排其它图片条目。";
    }

    private static string BuildE5ImageReplaceResultText(E5ImageReplaceResult result)
    {
        return
            $"E5 图片条目写入完成：{result.TargetRelativePath} #{result.ImageNumber}\r\n" +
            $"条目：offset=0x{result.OldDataOffset:X}/size={result.OldSizeBytes:N0}/{result.OldKind} -> offset=0x{result.NewDataOffset:X}/size={result.NewSizeBytes:N0}/{result.NewKind}\r\n" +
            $"写入方式：{result.Placement}    文件大小变化：{FormatSignedBytes(result.FileSizeDeltaBytes)}    改动估算：{result.ChangedBytesEstimate:N0} 字节\r\n" +
            $"备份：{result.BackupPath}\r\n报告：{result.ReportPath}\r\n结构化报告：{result.ReportJsonPath}";
    }

    private void ExportMissingImageResourceReport()
    {
        if (_currentImageAssignments == null)
        {
            MessageBox.Show(this, "\u8bf7\u5148\u8bfb\u53d6\u4eba\u7269 R/S\u3002", "\u63d0\u793a", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        var missingRows = _currentImageAssignments.Rows.Cast<DataRow>()
            .Where(row => IsImageResourceMissing(row, "R") || IsImageResourceMissing(row, "S"))
            .ToList();
        if (missingRows.Count == 0)
        {
            MessageBox.Show(this, "\u5f53\u524d\u4eba\u7269 R/S \u8054\u52a8\u8868\u6ca1\u6709\u68c0\u6d4b\u5230\u7f3a\u5931\u8d44\u6e90\u3002", "\u65e0\u9700\u5bfc\u51fa", MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        using var dialog = new SaveFileDialog
        {
            Title = "\u5bfc\u51fa R/S \u7f3a\u5931\u8d44\u6e90\u62a5\u544a",
            Filter = "CSV \u6587\u4ef6 (*.csv)|*.csv|\u6240\u6709\u6587\u4ef6 (*.*)|*.*",
            FileName = "\u4eba\u7269RS\u7f3a\u5931\u8d44\u6e90\u62a5\u544a.csv"
        };
        if (dialog.ShowDialog(this) != DialogResult.OK) return;

        try
        {
            var columns = _currentImageAssignments.Columns.Cast<DataColumn>().Select(c => c.ColumnName).ToList();
            var notes = new Dictionary<string, string>(StringComparer.Ordinal)
            {
                ["ID"] = "\u4eba\u7269\u884c\u53f7/\u7f16\u53f7\uff0c\u7528\u4e8e\u56de\u67e5\u4eba\u7269\u8868\u3002",
                ["\u540d\u79f0"] = "\u4eba\u7269\u540d\u79f0\u3002",
                ["R\u5f62\u8c61\u7f16\u53f7"] = "R \u5f62\u8c61\u7f16\u53f7\uff1a\u4eba\u7269\u6307\u5b9a\u8868\u4e2d\u7684\u7f16\u53f7 n\uff0c\u6309\u6559\u7a0b\u53e3\u5f84\u5b9a\u4f4d Pmapobj.e5 \u56fe 2n+1/2n+2\u3002",
                ["S\u5f62\u8c61\u7f16\u53f7"] = "S 形象紧凑编号：S=0 按职业和预览阵营取默认兵种图；S=1..32 对应三转特殊三张图；S>=33 从 Unit 图337 起对应一转特殊单张图。E5 索引表从 0x110 开始，每项 12 字节。",
                ["R\u8d44\u6e90\u72b6\u6001"] = "R \u8d44\u6e90\u5b9a\u4f4d\u68c0\u67e5\u7ed3\u679c\uff1a\u4e0d\u518d\u6309 RS\\R_XX.eex \u5224\u65ad\u4eba\u7269\u56fe\u50cf\u3002",
                ["S\u8d44\u6e90\u72b6\u6001"] = "S \u8d44\u6e90\u5b9a\u4f4d\u68c0\u67e5\u7ed3\u679c\uff1a\u4e0d\u518d\u6309 RS\\S_XX.eex \u5224\u65ad\u4eba\u7269\u56fe\u50cf\u3002"
            };
            CsvService.ExportColumnsRowsWithAnnotationRow(_currentImageAssignments, dialog.FileName, columns, notes, missingRows);
            Log($"\u5df2\u5bfc\u51fa R/S \u7f3a\u5931\u8d44\u6e90\u62a5\u544a\uff1a{dialog.FileName}\uff0c\u884c\u6570 {missingRows.Count}");
            SetStatus($"R/S \u7f3a\u5931\u8d44\u6e90\u62a5\u544a\u5bfc\u51fa\u5b8c\u6210\uff1a{missingRows.Count} \u884c");
        }
        catch (Exception ex)
        {
            Log("\u5bfc\u51fa R/S \u7f3a\u5931\u8d44\u6e90\u62a5\u544a\u5931\u8d25\uff1a" + ex);
            MessageBox.Show(this, ex.Message, "\u5bfc\u51fa\u5931\u8d25", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }

    private DataRow? GetSelectedImageAssignmentRow()
    {
        if (_imageAssignmentGrid.CurrentRow?.DataBoundItem is DataRowView rowView) return rowView.Row;
        if (_imageAssignmentGrid.SelectedRows.Count > 0 && _imageAssignmentGrid.SelectedRows[0].DataBoundItem is DataRowView selectedRowView) return selectedRowView.Row;
        return null;
    }

    private bool SelectImageAssignmentRow(Func<DataRow, bool> predicate, string preferredColumn)
    {
        _imageAssignmentGrid.ClearSelection();
        foreach (DataGridViewRow gridRow in _imageAssignmentGrid.Rows)
        {
            if (gridRow.DataBoundItem is not DataRowView rowView || !predicate(rowView.Row)) continue;

            var preferred = _imageAssignmentGrid.Columns
                .Cast<DataGridViewColumn>()
                .FirstOrDefault(column => column.Visible && column.DataPropertyName.Equals(preferredColumn, StringComparison.Ordinal));
            var cell = preferred != null
                ? gridRow.Cells[preferred.Index]
                : gridRow.Cells.Cast<DataGridViewCell>().FirstOrDefault(x => x.Visible);
            if (cell != null)
            {
                cell.Selected = true;
                _imageAssignmentGrid.CurrentCell = cell;
            }

            if (gridRow.Index >= 0 && gridRow.Index < _imageAssignmentGrid.RowCount)
            {
                _imageAssignmentGrid.FirstDisplayedScrollingRowIndex = gridRow.Index;
            }

            return true;
        }

        return false;
    }

    private string GetPreferredImageResourcePrefix()
    {
        if (_imageAssignmentGrid.CurrentCell != null)
        {
            var propertyName = _imageAssignmentGrid.Columns[_imageAssignmentGrid.CurrentCell.ColumnIndex].DataPropertyName;
            if (propertyName.StartsWith("S", StringComparison.Ordinal)) return "S";
        }

        return "R";
    }

    private static bool TryGetImageResourceId(DataRow row, string prefix, out int id)
    {
        var columnName = prefix == "S" ? "S\u5f62\u8c61\u7f16\u53f7" : "R\u5f62\u8c61\u7f16\u53f7";
        return int.TryParse(Convert.ToString(row[columnName], CultureInfo.InvariantCulture), NumberStyles.Integer, CultureInfo.InvariantCulture, out id);
    }

    private static bool IsImageResourceMissing(DataRow row, string prefix)
    {
        var columnName = prefix == "S" ? "S\u8d44\u6e90\u72b6\u6001" : "R\u8d44\u6e90\u72b6\u6001";
        return Convert.ToString(row[columnName], CultureInfo.InvariantCulture)?.StartsWith("\u7f3a\u5931", StringComparison.Ordinal) == true;
    }

    private void OpenFileLocation(string path)
    {
        try
        {
            Process.Start(new ProcessStartInfo
            {
                FileName = "explorer.exe",
                Arguments = $"/select,\"{path}\"",
                UseShellExecute = true
            });
            Log("\u5df2\u5b9a\u4f4d\u6587\u4ef6\uff1a" + path);
        }
        catch (Exception ex)
        {
            Log("\u5b9a\u4f4d\u6587\u4ef6\u5931\u8d25\uff1a" + ex);
            MessageBox.Show(this, ex.Message, "\u5b9a\u4f4d\u6587\u4ef6\u5931\u8d25", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }

    private void SaveImageAssignments()
    {
        if (_project == null || _currentImageAssignments == null) return;

        _imageAssignmentGrid.EndEdit();
        if (_currentImageAssignments.GetChanges() == null)
        {
            MessageBox.Show(this, "人物 R/S 形象没有检测到改动。", "无需保存", MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        var preview = BuildChangePreview(_currentImageAssignments, maxItems: 40);
        if (MessageBox.Show(this,
                $"即将保存人物 R/S 形象到当前 MOD 项目的 Ekd5.exe。\r\n\r\n变更预览：\r\n{preview}\r\n\r\n保存前会自动备份，保存后会重新读取校验。是否继续？",
                "确认保存人物 R/S",
                MessageBoxButtons.YesNo,
                MessageBoxIcon.Question) != DialogResult.Yes)
        {
            return;
        }

        try
        {
            Cursor = Cursors.WaitCursor;
            var result = _imageAssignmentService.Save(_project, _tables, _currentImageAssignments);
            _currentImageAssignments = _imageAssignmentService.Load(_project, _tables);
            _imageAssignmentGrid.DataSource = _currentImageAssignments;
            ColorImageAssignmentResourceRows();
            ShowSelectedImageAssignmentDetail();
            Log($"已保存人物 R/S 形象：保存表 {result.Saves.Count} 个，变化字节 {result.ChangedBytes}");
            Log("备份：" + result.BackupSummary);
            SetStatus($"人物 R/S 保存完成并已复读：变化 {result.ChangedBytes} 字节");
            MessageBox.Show(this,
                $"保存完成并已重新读取校验。\r\n保存表数量：{result.Saves.Count}\r\n变化字节：{result.ChangedBytes}\r\n备份：{result.BackupSummary}",
                "保存完成",
                MessageBoxButtons.OK,
                MessageBoxIcon.Information);
        }
        catch (Exception ex)
        {
            Log("保存人物 R/S 形象失败：" + ex);
            MessageBox.Show(this, ex.Message, "保存人物 R/S 形象失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
        finally
        {
            Cursor = Cursors.Default;
        }
    }

    private void ValidateImageAssignmentCell(DataGridViewCellValidatingEventArgs e)
    {
        if (_imageAssignmentGrid.ReadOnly || e.RowIndex < 0 || e.ColumnIndex < 0) return;
        if (_imageAssignmentGrid.Columns[e.ColumnIndex].ReadOnly) return;
        var columnName = _imageAssignmentGrid.Columns[e.ColumnIndex].DataPropertyName;
        if (columnName is not ("R形象编号" or "S形象编号")) return;

        var value = Convert.ToString(e.FormattedValue, CultureInfo.InvariantCulture) ?? string.Empty;
        var error = TryParseInteger(value, 0, ushort.MaxValue, columnName, _currentPageHexButton.Checked);
        _imageAssignmentGrid.Rows[e.RowIndex].Cells[e.ColumnIndex].ErrorText = error ?? string.Empty;
        if (error != null)
        {
            e.Cancel = true;
            SetStatus(error);
        }
    }

    private void SelectPatchFile()
    {
        var initial = ResolvePatchConfigInitialDirectory();

        using var dialog = new OpenFileDialog
        {
            Title = "选择普罗补丁文本",
            Filter = "文本补丁 (*.txt)|*.txt|所有文件 (*.*)|*.*",
            InitialDirectory = Directory.Exists(initial) ? initial : Directory.GetCurrentDirectory()
        };

        if (dialog.ShowDialog(this) != DialogResult.OK) return;
        _patchPathBox.Text = dialog.FileName;
        PreviewPatch();
    }

    private string ResolvePatchConfigInitialDirectory()
    {
        if (_project == null)
        {
            return Directory.GetCurrentDirectory();
        }

        if (!string.IsNullOrWhiteSpace(_project.PatchConfigRoot) &&
            Directory.Exists(_project.PatchConfigRoot))
        {
            return _project.PatchConfigRoot;
        }

        return ProjectDetector.FindPortableDirectory(_project, "普罗-搬运 注入", "普罗-搬运 注入")
            ?? Path.Combine(_project.WorkspaceRoot, "普罗-搬运 注入");
    }

    private void PreviewPatch()
    {
        if (_project == null)
        {
            MessageBox.Show(this, "请先加载项目。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        var patchPath = _patchPathBox.Text.Trim();
        if (string.IsNullOrWhiteSpace(patchPath) || !File.Exists(patchPath))
        {
            _applyPatchButton.Enabled = false;
            MessageBox.Show(this, "请先选择有效补丁文件。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        var target = Convert.ToString(_patchTargetCombo.SelectedItem, CultureInfo.InvariantCulture) ?? "Ekd5.exe";
        try
        {
            Cursor = Cursors.WaitCursor;
            _currentPatchDocument = _patchParser.Parse(patchPath);
            _currentPatchPreview = _patchService.Preview(_project, _currentPatchDocument, target);
            _patchGrid.DataSource = new BindingList<PatchPreviewRow>(_currentPatchPreview.Rows.ToList());
            ConfigurePatchGrid();
            _applyPatchButton.Enabled = _currentPatchPreview.CanApply;
            _patchInfoBox.Text =
                $"补丁：{_currentPatchDocument.SourcePath}\r\n" +
                $"版本：{_currentPatchDocument.Version}    地址类型：{_currentPatchDocument.AddressKind}    项数：{_currentPatchDocument.Entries.Count}\r\n" +
                $"目标：{_currentPatchPreview.TargetFilePath}\r\n" +
                $"可应用：{_currentPatchPreview.CanApply}    不可应用项：{_currentPatchPreview.WarningCount}    总字节：{_currentPatchPreview.TotalBytes}    将改变字节：{_currentPatchPreview.ChangedBytes}\r\n" +
                "当前项目允许应用补丁；写入前会自动备份目标文件，写入后生成报告。";

            Log($"已预览补丁：{patchPath}");
            Log($"补丁项：{_currentPatchDocument.Entries.Count}，目标：{target}，可应用：{_currentPatchPreview.CanApply}");
            SetStatus(_currentPatchPreview.CanApply ? "补丁预览完成" : "补丁存在不可应用项，请查看补丁页");
        }
        catch (Exception ex)
        {
            _applyPatchButton.Enabled = false;
            _patchInfoBox.Text = ex.ToString();
            Log("补丁预览失败：" + ex);
            MessageBox.Show(this, ex.Message, "补丁预览失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
        finally
        {
            Cursor = Cursors.Default;
        }
    }

    private void ConfigurePatchGrid()
    {
        foreach (DataGridViewColumn column in _patchGrid.Columns)
        {
            if (column.DataPropertyName is "OldBytesHex" or "NewBytesHex")
            {
                column.Width = 260;
            }
            if (column.DataPropertyName == nameof(PatchPreviewRow.Comment))
            {
                column.Width = 240;
            }
        }

        foreach (DataGridViewRow row in _patchGrid.Rows)
        {
            if (row.DataBoundItem is PatchPreviewRow previewRow && !previewRow.CanApply)
            {
                row.DefaultCellStyle.BackColor = Color.MistyRose;
            }
            else if (row.DataBoundItem is PatchPreviewRow { Changed: false })
            {
                row.DefaultCellStyle.BackColor = Color.Honeydew;
            }
        }
    }

    private void ApplyPatchToTestCopy()
    {
        if (_project == null || _currentPatchDocument == null || _currentPatchPreview == null)
        {
            return;
        }

        if (!_currentPatchPreview.CanApply)
        {
            MessageBox.Show(this, "补丁存在不可应用项，请先修正或更换目标文件。", "禁止应用", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        var target = Convert.ToString(_patchTargetCombo.SelectedItem, CultureInfo.InvariantCulture) ?? "Ekd5.exe";
        if (MessageBox.Show(this,
                $"即将把补丁应用到当前项目：\r\n{_currentPatchPreview.TargetFilePath}\r\n\r\n" +
                $"补丁项：{_currentPatchPreview.Rows.Count}\r\n写入字节：{_currentPatchPreview.TotalBytes}\r\n将改变字节：{_currentPatchPreview.ChangedBytes}\r\n\r\n" +
                "写入前会自动备份目标文件并生成报告。是否继续？",
                "确认应用补丁",
                MessageBoxButtons.YesNo,
                MessageBoxIcon.Warning) != DialogResult.Yes)
        {
            return;
        }

        try
        {
            Cursor = Cursors.WaitCursor;
            var result = _patchService.Apply(_project, _currentPatchDocument, target);
            Log($"已应用补丁：{_currentPatchDocument.SourcePath}");
            Log($"目标文件：{result.TargetFilePath}");
            Log($"备份：{result.BackupPath}");
            Log($"报告：{result.ReportPath}");
            Log($"结构化报告：{result.ReportJsonPath}");
            SetStatus($"补丁应用完成：{result.EntriesApplied} 项，变化 {result.ChangedBytes} 字节");
            MessageBox.Show(this,
                $"补丁应用完成。\r\n项数：{result.EntriesApplied}\r\n写入字节：{result.BytesWritten}\r\n变化字节：{result.ChangedBytes}\r\n备份：{result.BackupPath}\r\n报告：{result.ReportPath}\r\n结构化报告：{result.ReportJsonPath}",
                "补丁应用完成",
                MessageBoxButtons.OK,
                MessageBoxIcon.Information);
            PreviewPatch();
        }
        catch (Exception ex)
        {
            Log("补丁应用失败：" + ex);
            MessageBox.Show(this, ex.Message, "补丁应用失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
        finally
        {
            Cursor = Cursors.Default;
        }
    }

    private void SelectBatchMoveFile()
    {
        var initial = ResolvePatchConfigInitialDirectory();

        using var dialog = new OpenFileDialog
        {
            Title = "选择普罗批量搬运配置",
            Filter = "文本配置 (*.txt)|*.txt|所有文件 (*.*)|*.*",
            InitialDirectory = Directory.Exists(initial) ? initial : Directory.GetCurrentDirectory()
        };

        if (dialog.ShowDialog(this) != DialogResult.OK) return;
        _movePathBox.Text = dialog.FileName;
        PreviewBatchMove();
    }

    private void PreviewBatchMove()
    {
        var path = _movePathBox.Text.Trim();
        if (string.IsNullOrWhiteSpace(path) || !File.Exists(path))
        {
            MessageBox.Show(this, "请先选择有效搬运配置文件。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        try
        {
            _currentBatchMoveDocument = _batchMoveParser.Parse(path);
            _moveGrid.DataSource = new BindingList<BatchMoveEntry>(_currentBatchMoveDocument.Entries.ToList());
            var totalLength = _currentBatchMoveDocument.Entries.Sum(e => e.Length);
            _moveInfoBox.Text =
                $"配置：{_currentBatchMoveDocument.SourcePath}\r\n" +
                $"条目：{_currentBatchMoveDocument.Entries.Count}    总长度（按十进制长度解释）：{totalLength} 字节\r\n" +
                "当前阶段只做配置解析和报告预览，不执行跨版本搬运写入；写入功能必须在确认源/目标版本和长度单位后再开放。";
            Log($"已预览搬运配置：{path}，条目 {_currentBatchMoveDocument.Entries.Count}");
            SetStatus("搬运配置预览完成");
        }
        catch (Exception ex)
        {
            _moveInfoBox.Text = ex.ToString();
            Log("搬运配置预览失败：" + ex);
            MessageBox.Show(this, ex.Message, "搬运配置预览失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }

    private void LoadSceneDictionary() => LoadSceneDictionary(showMessages: true);

    private bool LoadSceneDictionary(bool showMessages)
    {
        var workspace = _project?.WorkspaceRoot ?? Directory.GetCurrentDirectory();
        var path = _project == null ? ProjectDetector.FindSceneDictionaryPath(workspace) : ProjectDetector.FindSceneDictionaryPath(_project);
        if (!File.Exists(path))
        {
            var message = "找不到 CczString.ini：" + path + "\r\n\r\n请把 CczString.ini 放到当前项目的 a新剧本编辑器v0.23 目录，或确认工具内置 LegacyResources 备份未被删除。";
            _sceneDictionaryInfoBox.Text = message;
            Log("剧本字典未找到：" + path);
            if (showMessages)
            {
                MessageBox.Show(this, message, "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                SetStatus("剧本字典未找到");
            }

            return false;
        }

        try
        {
            _currentSceneStringDocument = _sceneStringParser.Parse(path);
            _sceneCommandGrid.DataSource = new BindingList<SceneCommandDefinition>(_currentSceneStringDocument.Commands.ToList());
            _sceneGroupGrid.DataSource = new BindingList<SceneStringGroup>(_currentSceneStringDocument.Groups.ToList());
            _sceneDictionaryInfoBox.Text =
                $"来源：{_currentSceneStringDocument.SourcePath}\r\n" +
                $"命令字典：{_currentSceneStringDocument.Commands.Count} 项    附加字符串组：{_currentSceneStringDocument.Groups.Count} 组\r\n" +
                "当前阶段用于剧本模块的命令 ID->名称映射和参数候选表预览，尚未开放 Scene 二进制结构写入。";
            PopulateScriptNewCommandCombo(_currentSceneStringDocument);
            _probeScenarioCommandsButton.Enabled = _currentScenarioFiles.Count > 0;
            _buildScenarioStructureButton.Enabled = _currentScenarioFiles.Count > 0;
            if (showMessages)
            {
                LoadScenarioCommandTemplates(silent: true);
            }

            Log($"已读取剧本字典：命令 {_currentSceneStringDocument.Commands.Count} 项，字符串组 {_currentSceneStringDocument.Groups.Count} 组。");
            if (showMessages)
            {
                SetStatus("剧本字典读取完成");
            }

            return true;
        }
        catch (Exception ex)
        {
            _sceneDictionaryInfoBox.Text = ex.ToString();
            Log("剧本字典读取失败：" + ex);
            if (showMessages)
            {
                MessageBox.Show(this, ex.Message, "剧本字典读取失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }

            return false;
        }
    }

    private void IndexMaterialLibrary() => IndexMaterialLibrary(showMessages: true);

    private bool IndexMaterialLibrary(bool showMessages)
    {
        var workspace = _project?.WorkspaceRoot ?? Directory.GetCurrentDirectory();
        try
        {
            var resolvedRoot = _project == null
                ? MaterialLibraryIndexer.ResolveMaterialLibraryRoot(workspace)
                : MaterialLibraryIndexer.ResolveMaterialLibraryRoot(_project);
            var materialRoot = resolvedRoot
                ?? Path.Combine(workspace, "普罗-综合工具v0.3", "素材库");
            _currentMaterialAssets = _project == null
                ? _materialLibraryIndexer.Index(workspace)
                : _materialLibraryIndexer.Index(_project);
            _materialGrid.DataSource = new BindingList<MaterialAsset>(_currentMaterialAssets.ToList());
            var categorySummary = string.Join("，", _currentMaterialAssets
                .GroupBy(x => x.Category)
                .Select(g => $"{g.Key}:{g.Count()}"));
            _materialInfoBox.Text =
                $"素材根目录：{materialRoot}\r\n" +
                $"素材数量：{_currentMaterialAssets.Count}    分类：{categorySummary}\r\n" +
                "当前阶段提供素材索引、hex 标记/说明和图片预览；地图写入和素材导入需等待地图格式验证。";
            Log($"已索引素材库：{_currentMaterialAssets.Count} 个图片素材。");
            if (resolvedRoot == null)
            {
                Log("素材库目录未找到，当前素材索引为空：" + materialRoot);
            }

            if (showMessages)
            {
                SetStatus("素材库索引完成");
            }

            return true;
        }
        catch (Exception ex)
        {
            _materialInfoBox.Text = ex.ToString();
            Log("素材库索引失败：" + ex);
            if (showMessages)
            {
                MessageBox.Show(this, ex.Message, "素材库索引失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }

            return false;
        }
    }

    private void ShowSelectedMaterialPreview()
    {
        if (_materialGrid.SelectedRows.Count == 0) return;
        if (_materialGrid.SelectedRows[0].DataBoundItem is not MaterialAsset asset) return;

        try
        {
            var old = _materialPreview.Image;
            _materialPreview.Image = null;
            old?.Dispose();
            using var source = Image.FromFile(asset.FilePath);
            _materialPreview.Image = new Bitmap(source);
            SetStatus($"素材预览：{asset.Category}/{asset.FileName}");
        }
        catch (Exception ex)
        {
            var old = _materialPreview.Image;
            _materialPreview.Image = null;
            old?.Dispose();
            Log($"素材预览失败：{asset.FilePath} {ex.Message}");
        }
    }

    private void IndexGameResources()
    {
        if (_project == null)
        {
            MessageBox.Show(this, "请先加载项目。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        try
        {
            Cursor = Cursors.WaitCursor;
            _currentGameResources = _gameResourceIndexer.Index(_project);
            PopulateGameResourceCategoryFilter();
            BindGameResourceRows(_currentGameResources);
            var summary = string.Join("，", _currentGameResources
                .GroupBy(x => x.Category)
                .OrderBy(g => g.Key)
                .Select(g => $"{g.Key}:{g.Count()}"));
            _gameResourceInfoBox.Text =
                $"游戏资源根目录：{_project.GameRoot}\r\n" +
                $"索引项：{_currentGameResources.Count}    分类：{summary}\r\n" +
                "当前阶段可索引、预览、定位、导出资源；已索引资源支持整文件替换预览、自动备份和从备份还原。EEX/E5S/E5 的内部重封包仍需后续格式验证。";
            var maps = _currentGameResources
                .Where(x => x.Category == "地图图片")
                .OrderBy(x => x.Id)
                .ThenBy(x => x.Name, StringComparer.CurrentCultureIgnoreCase)
                .ToList();
            _mapImageList.DisplayMember = nameof(ResourceIndexItem.Name);
            _mapImageList.DataSource = new BindingList<ResourceIndexItem>(maps);
            Log($"已索引游戏资源：{_currentGameResources.Count} 项。");
            SetStatus("游戏资源索引完成");
        }
        catch (Exception ex)
        {
            _gameResourceInfoBox.Text = ex.ToString();
            Log("游戏资源索引失败：" + ex);
            MessageBox.Show(this, ex.Message, "游戏资源索引失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
        finally
        {
            Cursor = Cursors.Default;
        }
    }

    private void BindGameResourceRows(IEnumerable<ResourceIndexItem> rows)
    {
        _gameResourceGrid.DataSource = new BindingList<ResourceIndexItem>(rows.ToList());
        HighlightRowsWithCreatorNotes<ResourceIndexItem>(
            _gameResourceGrid,
            item => ("游戏资源", $"{item.Category}/{item.Name}"));
    }

    private void PopulateGameResourceCategoryFilter()
    {
        var previous = Convert.ToString(_gameResourceCategoryFilterCombo.SelectedItem, CultureInfo.InvariantCulture);
        _gameResourceCategoryFilterCombo.Items.Clear();
        _gameResourceCategoryFilterCombo.Items.Add("\u5168\u90e8");
        foreach (var category in _currentGameResources.Select(x => x.Category).Distinct().OrderBy(x => x, StringComparer.CurrentCultureIgnoreCase))
        {
            _gameResourceCategoryFilterCombo.Items.Add(category);
        }

        var selectedIndex = 0;
        if (!string.IsNullOrWhiteSpace(previous))
        {
            for (var i = 0; i < _gameResourceCategoryFilterCombo.Items.Count; i++)
            {
                if (string.Equals(Convert.ToString(_gameResourceCategoryFilterCombo.Items[i], CultureInfo.InvariantCulture), previous, StringComparison.Ordinal))
                {
                    selectedIndex = i;
                    break;
                }
            }
        }
        _gameResourceCategoryFilterCombo.SelectedIndex = selectedIndex;
    }

    private void ApplyGameResourceFilter()
    {
        if (_currentGameResources.Count == 0) return;
        var category = Convert.ToString(_gameResourceCategoryFilterCombo.SelectedItem, CultureInfo.InvariantCulture) ?? "\u5168\u90e8";
        var keyword = _gameResourceSearchBox.Text.Trim();
        var filtered = _currentGameResources.Where(item =>
            (category == "\u5168\u90e8" || string.Equals(item.Category, category, StringComparison.Ordinal)) &&
            (string.IsNullOrWhiteSpace(keyword) || GameResourceMatchesKeyword(item, keyword)))
            .ToList();
        BindGameResourceRows(filtered);
        UpdateGameResourceInfo(filtered.Count, category, keyword);
        SetStatus($"\u6e38\u620f\u8d44\u6e90\u7b5b\u9009\uff1a{filtered.Count}/{_currentGameResources.Count}");
    }

    private void ClearGameResourceFilter()
    {
        _gameResourceSearchBox.Clear();
        if (_gameResourceCategoryFilterCombo.Items.Count > 0) _gameResourceCategoryFilterCombo.SelectedIndex = 0;
        BindGameResourceRows(_currentGameResources);
        UpdateGameResourceInfo(_currentGameResources.Count, "\u5168\u90e8", string.Empty);
        SetStatus("\u5df2\u663e\u793a\u5168\u90e8\u6e38\u620f\u8d44\u6e90");
    }

    private static bool GameResourceMatchesKeyword(ResourceIndexItem item, string keyword)
    {
        return ContainsKeyword(item.Category, keyword) ||
               ContainsKeyword(item.Id, keyword) ||
               ContainsKeyword(item.Name, keyword) ||
               ContainsKeyword(item.Extension, keyword) ||
               ContainsKeyword(item.Magic, keyword) ||
               ContainsKeyword(item.FormatHint, keyword) ||
               ContainsKeyword(item.Annotation, keyword) ||
               ContainsKeyword(item.Path, keyword);
    }

    private static bool ContainsKeyword(string value, string keyword) =>
        value.Contains(keyword, StringComparison.CurrentCultureIgnoreCase);

    private void UpdateGameResourceInfo(int visibleCount, string category, string keyword)
    {
        if (_project == null) return;
        var summary = string.Join("\uff0c", _currentGameResources
            .GroupBy(x => x.Category)
            .OrderBy(g => g.Key)
            .Select(g => $"{g.Key}:{g.Count()}"));
        var filterText = category == "\u5168\u90e8" && string.IsNullOrWhiteSpace(keyword)
            ? "\u672a\u7b5b\u9009"
            : $"\u5206\u7c7b={category}\uff0c\u5173\u952e\u5b57={keyword}";
        _gameResourceInfoBox.Text =
            $"\u6e38\u620f\u8d44\u6e90\u6839\u76ee\u5f55\uff1a{_project.GameRoot}\r\n" +
            $"\u7d22\u5f15\u9879\uff1a{_currentGameResources.Count}    \u5f53\u524d\u663e\u793a\uff1a{visibleCount}    \u5206\u7c7b\uff1a{summary}\r\n" +
            $"\u7b5b\u9009\uff1a{filterText}\r\n" +
            "当前阶段可索引、预览、定位、导出资源；已索引资源支持整文件替换预览、自动备份和从备份还原。EEX/E5S/E5 的内部解码、扩容和重封包仍需后续格式验证。";
    }

    private void OpenSelectedGameResourceLocation()
    {
        var item = GetSelectedGameResourceItem();
        if (item == null)
        {
            MessageBox.Show(this, "\u8bf7\u5148\u5728\u6e38\u620f\u8d44\u6e90\u7d22\u5f15\u9875\u9009\u62e9\u4e00\u4e2a\u6587\u4ef6\u3002", "\u63d0\u793a", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        if (!File.Exists(item.Path) && !Directory.Exists(item.Path))
        {
            MessageBox.Show(this, "\u627e\u4e0d\u5230\u8d44\u6e90\u6587\u4ef6\uff1a" + item.Path, "\u63d0\u793a", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        OpenFileLocation(item.Path);
        SetStatus($"\u5df2\u5b9a\u4f4d\u8d44\u6e90\uff1a{item.Category}/{item.Name}");
    }

    private void ReplaceSelectedGameResourceInTestCopy()
    {
        if (_project == null)
        {
            MessageBox.Show(this, "请先加载项目。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        var item = GetSelectedGameResourceItem();
        if (item == null)
        {
            MessageBox.Show(this, "请先在游戏资源索引页选择一个文件。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        if (!File.Exists(item.Path))
        {
            MessageBox.Show(this, "选中资源文件不存在：" + item.Path, "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        var extension = string.IsNullOrWhiteSpace(item.Extension) ? Path.GetExtension(item.Path) : item.Extension;
        using var dialog = new OpenFileDialog
        {
            Title = "选择替换来源文件",
            Filter = string.IsNullOrWhiteSpace(extension)
                ? "所有文件 (*.*)|*.*"
                : $"同类资源 (*{extension})|*{extension}|所有文件 (*.*)|*.*",
            CheckFileExists = true
        };
        if (dialog.ShowDialog(this) != DialogResult.OK) return;

        ResourceReplacePreviewResult preview;
        try
        {
            Cursor = Cursors.WaitCursor;
            preview = _resourceReplaceService.PreviewReplacement(_project, item.Path, dialog.FileName);
            _gameResourceInfoBox.Text = BuildResourceReplacePreviewText(item, preview);
            Log($"资源替换预览：{preview.TargetRelativePath} <- {preview.ReplacementPath}，改动估算 {preview.ChangedBytesEstimate:N0} 字节");
            SetStatus("资源替换预览完成，请确认");
        }
        catch (Exception ex)
        {
            Log("资源替换预览失败：" + ex);
            MessageBox.Show(this, ex.Message, "替换预览失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
            return;
        }
        finally
        {
            Cursor = Cursors.Default;
        }

        var confirm = ShowResourceReplacePreviewDialog("确认替换项目资源", "确认替换", item, preview, BuildResourceReplaceConfirmText(item, preview));
        if (confirm != DialogResult.Yes) return;

        try
        {
            Cursor = Cursors.WaitCursor;
            var result = _resourceReplaceService.Replace(_project, item.Path, dialog.FileName);
            _currentGameResources = _gameResourceIndexer.Index(_project);
            PopulateGameResourceCategoryFilter();
            BindGameResourceRows(_currentGameResources);
            UpdateGameResourceInfo(_currentGameResources.Count, "全部", string.Empty);
            _gameResourceInfoBox.Text =
                $"资源替换完成：{item.Category}/{item.Name}\r\n" +
                $"旧大小：{result.OldSizeBytes:N0} 字节    新大小：{result.NewSizeBytes:N0} 字节    改动估算：{result.ChangedBytesEstimate:N0} 字节\r\n" +
                $"格式检查：{result.FormatCheckSummary}\r\n" +
                $"格式警告：{(result.FormatWarnings.Count == 0 ? "无" : string.Join("；", result.FormatWarnings))}\r\n" +
                $"风险提示：{result.RiskSummary}\r\n" +
                $"备份：{result.BackupPath}\r\n报告：{result.ReportPath}\r\n结构化报告：{result.ReportJsonPath}\r\n" +
                "说明：这是项目资源整文件替换，不会重封包未知格式；替换后请运行资源诊断和实机测试。";
            RefreshResourceDiagnosticsAfterFileChange(item);
            Log($"已替换项目资源：{item.Path} <- {dialog.FileName}，备份 {result.BackupPath}，结构化报告 {result.ReportJsonPath}");
            SetStatus("项目资源替换完成");
        }
        catch (Exception ex)
        {
            Log("替换项目资源失败：" + ex);
            MessageBox.Show(this, ex.Message, "替换失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
        finally
        {
            Cursor = Cursors.Default;
        }
    }

    private void RestoreSelectedGameResourceFromBackup()
    {
        if (_project == null)
        {
            MessageBox.Show(this, "请先加载项目。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        var item = GetSelectedGameResourceItem();
        if (item == null)
        {
            MessageBox.Show(this, "请先在游戏资源索引页选择一个要还原的文件。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        if (!File.Exists(item.Path))
        {
            MessageBox.Show(this, "选中资源文件不存在：" + item.Path, "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        var backupRoot = Path.Combine(_project.GameRoot, "_CCZModStudio_Backups");
        if (!Directory.Exists(backupRoot))
        {
            MessageBox.Show(this, "当前项目还没有备份目录：" + backupRoot, "没有可用备份", MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        var extension = string.IsNullOrWhiteSpace(item.Extension) ? Path.GetExtension(item.Path) : item.Extension;
        using var dialog = new OpenFileDialog
        {
            Title = "选择用于还原的备份文件",
            InitialDirectory = backupRoot,
            Filter = string.IsNullOrWhiteSpace(extension)
                ? "所有备份文件 (*.*)|*.*"
                : $"同扩展名备份 (*{extension})|*{extension}|所有文件 (*.*)|*.*",
            CheckFileExists = true
        };
        if (dialog.ShowDialog(this) != DialogResult.OK) return;

        ResourceReplacePreviewResult preview;
        try
        {
            Cursor = Cursors.WaitCursor;
            preview = _resourceReplaceService.PreviewReplacement(_project, item.Path, dialog.FileName);
            _gameResourceInfoBox.Text =
                "资源备份还原预览：将把所选备份整文件写回当前项目资源。\r\n" +
                BuildResourceReplacePreviewText(item, preview);
            Log($"资源备份还原预览：{preview.TargetRelativePath} <- {preview.ReplacementPath}");
            SetStatus("资源备份还原预览完成，请确认");
        }
        catch (Exception ex)
        {
            Log("资源备份还原预览失败：" + ex);
            MessageBox.Show(this, ex.Message, "还原预览失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
            return;
        }
        finally
        {
            Cursor = Cursors.Default;
        }

        var confirm = ShowResourceReplacePreviewDialog(
            "确认从备份还原",
            "确认还原",
            item,
            preview,
            "即将从备份文件还原选中资源。\r\n\r\n" +
            BuildResourceReplaceConfirmText(item, preview) +
            "\r\n\r\n注意：还原前仍会自动备份当前文件，因此可以再次回退。");
        if (confirm != DialogResult.Yes) return;

        try
        {
            Cursor = Cursors.WaitCursor;
            var result = _resourceReplaceService.Replace(_project, item.Path, dialog.FileName);
            _currentGameResources = _gameResourceIndexer.Index(_project);
            PopulateGameResourceCategoryFilter();
            BindGameResourceRows(_currentGameResources);
            UpdateGameResourceInfo(_currentGameResources.Count, "全部", string.Empty);
            _gameResourceInfoBox.Text =
                $"资源备份还原完成：{item.Category}/{item.Name}\r\n" +
                $"旧大小：{result.OldSizeBytes:N0} 字节    还原后大小：{result.NewSizeBytes:N0} 字节    改动估算：{result.ChangedBytesEstimate:N0} 字节\r\n" +
                $"格式检查：{result.FormatCheckSummary}\r\n" +
                $"格式警告：{(result.FormatWarnings.Count == 0 ? "无" : string.Join("；", result.FormatWarnings))}\r\n" +
                $"风险提示：{result.RiskSummary}\r\n" +
                $"还原前当前文件备份：{result.BackupPath}\r\n报告：{result.ReportPath}\r\n结构化报告：{result.ReportJsonPath}\r\n" +
                "说明：已从选定备份整文件还原到当前项目；建议重新运行资源诊断和差异检查。";
            RefreshResourceDiagnosticsAfterFileChange(item);
            Log($"已从备份还原项目资源：{item.Path} <- {dialog.FileName}，还原前备份 {result.BackupPath}，结构化报告 {result.ReportJsonPath}");
            SetStatus("项目资源备份还原完成");
        }
        catch (Exception ex)
        {
            Log("从备份还原资源失败：" + ex);
            MessageBox.Show(this, ex.Message, "还原失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
        finally
        {
            Cursor = Cursors.Default;
        }
    }

    private static string BuildResourceReplacePreviewText(ResourceIndexItem item, ResourceReplacePreviewResult preview)
    {
        return
            $"资源替换预览：{item.Category}/{item.Name}    ID={item.Id}\r\n" +
            $"目标：{preview.TargetRelativePath}\r\n" +
            $"来源：{preview.ReplacementPath}\r\n" +
            $"大小：目标 {preview.OldSizeBytes:N0} 字节 -> 来源 {preview.NewSizeBytes:N0} 字节（差值 {FormatSignedBytes(preview.SizeDeltaBytes)}）\r\n" +
            $"改动估算：{preview.ChangedBytesEstimate:N0} 字节（约 {preview.ChangedPercent:F2}%）；内容相同：{(preview.IsContentIdentical ? "是" : "否")}\r\n" +
            $"SHA256：目标 {ShortSha256(preview.OldSha256)}    来源 {ShortSha256(preview.NewSha256)}\r\n" +
            $"格式检查：{preview.FormatCheckSummary}\r\n" +
            $"格式警告：{(preview.FormatWarnings.Count == 0 ? "无" : string.Join("；", preview.FormatWarnings))}\r\n" +
            $"风险提示：{preview.RiskSummary}\r\n" +
            "说明：这只是预览，尚未写入。确认后会先备份目标文件，再进行整文件替换。";
    }

    private static string BuildResourceReplaceConfirmText(ResourceIndexItem item, ResourceReplacePreviewResult preview)
    {
        return
            $"将用来源文件替换项目资源：\r\n\r\n" +
            $"资源：{item.Category}/{item.Name}\r\n" +
            $"目标：{preview.TargetRelativePath}\r\n" +
            $"来源：{preview.ReplacementPath}\r\n\r\n" +
            $"大小变化：{preview.OldSizeBytes:N0} -> {preview.NewSizeBytes:N0} 字节（{FormatSignedBytes(preview.SizeDeltaBytes)}）\r\n" +
            $"改动估算：{preview.ChangedBytesEstimate:N0} 字节，约 {preview.ChangedPercent:F2}%\r\n" +
            $"SHA256：{ShortSha256(preview.OldSha256)} -> {ShortSha256(preview.NewSha256)}\r\n" +
            $"格式检查：{preview.FormatCheckSummary}\r\n" +
            $"格式警告：{(preview.FormatWarnings.Count == 0 ? "无" : string.Join("；", preview.FormatWarnings))}\r\n\r\n" +
            $"风险提示：{preview.RiskSummary}\r\n\r\n" +
            "选择“是”后会先备份目标文件，再写入当前项目。是否继续？";
    }

    private DialogResult ShowResourceReplacePreviewDialog(string title, string confirmText, ResourceIndexItem item, ResourceReplacePreviewResult preview, string detailText)
    {
        using var dialog = new Form
        {
            Text = title,
            StartPosition = FormStartPosition.CenterParent,
            MinimizeBox = false,
            MaximizeBox = true,
            ShowInTaskbar = false
        };
        ApplyAdaptiveDialogSizing(dialog, new Size(1100, 760), new Size(840, 560));

        var layout = new TableLayoutPanel
        {
            Dock = DockStyle.Fill,
            RowCount = 3,
            ColumnCount = 1,
            Padding = new Padding(10)
        };
        layout.RowStyles.Add(new RowStyle(SizeType.Absolute, 210));
        layout.RowStyles.Add(new RowStyle(SizeType.Percent, 100));
        layout.RowStyles.Add(new RowStyle(SizeType.AutoSize));
        dialog.Controls.Add(layout);

        var infoBox = new TextBox
        {
            Dock = DockStyle.Fill,
            Multiline = true,
            ReadOnly = true,
            ScrollBars = ScrollBars.Vertical,
            WordWrap = false,
            Text = detailText
        };
        layout.Controls.Add(infoBox, 0, 0);

        var imageSplit = new SplitContainer
        {
            Dock = DockStyle.Fill,
            Orientation = Orientation.Vertical,
        };
        ConfigureSplitContainerDistanceAfterLayout(imageSplit, desiredDistance: 520, desiredPanel1Min: 25, desiredPanel2Min: 25);
        layout.Controls.Add(imageSplit, 0, 1);
        imageSplit.Panel1.Controls.Add(BuildResourcePreviewPanel("当前目标文件", preview.TargetPath, $"{item.Category}/{item.Name}", disposeOnClose: dialog));
        imageSplit.Panel2.Controls.Add(BuildResourcePreviewPanel("替换/还原来源文件", preview.ReplacementPath, Path.GetFileName(preview.ReplacementPath), disposeOnClose: dialog));

        var buttonPanel = new FlowLayoutPanel
        {
            Dock = DockStyle.Fill,
            AutoSize = true,
            FlowDirection = FlowDirection.RightToLeft,
            Padding = new Padding(0, 10, 0, 0)
        };
        var confirmButton = new Button
        {
            Text = confirmText,
            DialogResult = DialogResult.Yes,
            AutoSize = true,
            MinimumSize = new Size(120, 34)
        };
        var cancelButton = new Button
        {
            Text = "取消",
            DialogResult = DialogResult.Cancel,
            AutoSize = true,
            MinimumSize = new Size(100, 34)
        };
        buttonPanel.Controls.Add(confirmButton);
        buttonPanel.Controls.Add(cancelButton);
        layout.Controls.Add(buttonPanel, 0, 2);
        dialog.AcceptButton = confirmButton;
        dialog.CancelButton = cancelButton;

        return dialog.ShowDialog(this);
    }

    private void RefreshResourceDiagnosticsAfterFileChange(ResourceIndexItem changedItem)
    {
        if (_project == null)
        {
            return;
        }

        try
        {
            var shouldReviewScenarioMap = _resourceChangeReviewHintService.MayAffectScenarioMap(changedItem);
            if (shouldReviewScenarioMap)
            {
                InvalidateScenarioMapCachesAfterResourceChange(changedItem);
            }

            RunResourceDiagnostics();
            var errors = _currentResourceDiagnostics.Count(x => x.Severity == "Error");
            var warnings = _currentResourceDiagnostics.Count(x => x.Severity == "Warn");
            var infos = _currentResourceDiagnostics.Count(x => x.Severity == "Info");
            var related = _currentResourceDiagnostics
                .Where(x => ResourceDiagnosticMayRelateToResource(x, changedItem))
                .Take(5)
                .ToList();
            var relatedText = related.Count == 0
                ? "未发现与当前资源直接匹配的诊断项。"
                : "可能相关诊断：" + string.Join("；", related.Select(x => $"[{x.Severity}] {x.Category}/{x.Rule}:{x.Status}"));
            var scenarioMapReviewText = shouldReviewScenarioMap
                ? RefreshScenarioMapReviewAfterResourceChange(changedItem)
                : string.Empty;
            _gameResourceInfoBox.AppendText(
                $"\r\n\r\n已自动刷新资源诊断：Error={errors}，Warn={warnings}，Info={infos}。\r\n" +
                relatedText +
                (string.IsNullOrWhiteSpace(scenarioMapReviewText) ? string.Empty : "\r\n\r\n" + scenarioMapReviewText));
            Log($"资源变更后已自动刷新诊断：{changedItem.Name}，Error={errors}，Warn={warnings}，Info={infos}，相关 {related.Count} 项，联动复查={(shouldReviewScenarioMap ? "已提示" : "不适用")}。");
        }
        catch (Exception ex)
        {
            _gameResourceInfoBox.AppendText("\r\n\r\n资源已写入，但自动刷新资源诊断失败：" + ex.Message + "\r\n请手动切换到“资源诊断”页重新诊断。");
            Log("资源变更后自动刷新诊断失败：" + ex);
        }
    }

    private void InvalidateScenarioMapCachesAfterResourceChange(ResourceIndexItem changedItem)
    {
        _currentScenarioMapLinks = Array.Empty<ScenarioMapLinkInfo>();

        if (changedItem.Category == "E5S存档信息" || PathContainsDirectorySegment(changedItem.Path, "RS"))
        {
            _currentScenarioFiles = Array.Empty<ScenarioFileInfo>();
        }

        if (changedItem.Name.Equals("Hexzmap.e5", StringComparison.OrdinalIgnoreCase))
        {
            _currentHexzmapProbe = null;
        }
    }

    private string RefreshScenarioMapReviewAfterResourceChange(ResourceIndexItem changedItem)
    {
        try
        {
            if (_currentScenarioMapLinks.Count == 0)
            {
                _currentScenarioMapLinks = EnsureScenarioMapLinksForDiagnostics();
            }

            if (_currentScenarioMapLinks.Count > 0)
            {
                PopulateScenarioMapLinkStatusFilter();
                BindScenarioMapLinkRows(_currentScenarioMapLinks);
                _exportScenarioMapLinksCsvButton.Enabled = true;
                _locateScenarioMapScenarioButton.Enabled = true;
                _locateScenarioMapImageButton.Enabled = _currentScenarioMapLinks.Any(x => x.MapImageExists);
                _jumpScenarioMapScenarioButton.Enabled = true;
                _jumpScenarioMapHexzmapButton.Enabled = _currentScenarioMapLinks.Any(x => x.HexzmapBlockExists);
                _jumpScenarioMapViewerButton.Enabled = _currentScenarioMapLinks.Any(x => x.MapImageExists);
                _exportScenarioMapPreviewPngButton.Enabled = _currentScenarioMapLinks.Any(x => x.MapImageExists || x.HexzmapBlockExists);
                _writeScenarioMapReportButton.Enabled = true;
                _filterScenarioMapLinksButton.Enabled = true;
                _clearScenarioMapLinkFilterButton.Enabled = true;
                _scenarioMapLinksIncompleteOnly.Enabled = true;
                UpdateScenarioMapLinkSummary(_currentScenarioMapLinks.Count, "全部", string.Empty, false);
            }

            return _resourceChangeReviewHintService.BuildScenarioMapReviewHint(changedItem, _currentScenarioMapLinks);
        }
        catch (Exception ex)
        {
            Log("资源变更后刷新关卡地图联动复查提示失败：" + ex);
            return "关卡地图联动复查：资源可能影响地图/R/S eex/Hexzmap 联动，但自动重新生成联动提示失败。请手动打开“关卡地图联动”页重新生成、导出检查报告和预览 PNG。错误：" + ex.Message;
        }
    }

    private static bool PathContainsDirectorySegment(string path, string segment)
    {
        if (string.IsNullOrWhiteSpace(path)) return false;
        var normalized = path.Replace('/', '\\');
        return normalized.Contains("\\" + segment + "\\", StringComparison.OrdinalIgnoreCase);
    }

    private static bool ResourceDiagnosticMayRelateToResource(ResourceDiagnosticItem diagnostic, ResourceIndexItem item)
    {
        var fileName = Path.GetFileName(item.Path);
        return (!string.IsNullOrWhiteSpace(diagnostic.Path) && Path.GetFullPath(diagnostic.Path).Equals(Path.GetFullPath(item.Path), StringComparison.OrdinalIgnoreCase)) ||
               ContainsKeyword(diagnostic.Path, fileName) ||
               ContainsKeyword(diagnostic.Name, item.Name) ||
               (!string.IsNullOrWhiteSpace(item.Id) && ContainsKeyword(diagnostic.Id, item.Id)) ||
               (!string.IsNullOrWhiteSpace(item.Category) && ContainsKeyword(diagnostic.Category, item.Category));
    }

    private static Control BuildResourcePreviewPanel(string title, string path, string subtitle, Form disposeOnClose)
    {
        var panel = new TableLayoutPanel
        {
            Dock = DockStyle.Fill,
            RowCount = 3,
            ColumnCount = 1,
            Padding = new Padding(6)
        };
        panel.RowStyles.Add(new RowStyle(SizeType.AutoSize));
        panel.RowStyles.Add(new RowStyle(SizeType.Percent, 100));
        panel.RowStyles.Add(new RowStyle(SizeType.AutoSize));

        var titleLabel = new Label
        {
            Dock = DockStyle.Fill,
            AutoSize = true,
            Font = new Font(SystemFonts.DefaultFont, FontStyle.Bold),
            Text = title + "： " + subtitle
        };
        panel.Controls.Add(titleLabel, 0, 0);

        var previewBox = new PictureBox
        {
            Dock = DockStyle.Fill,
            BorderStyle = BorderStyle.FixedSingle,
            SizeMode = PictureBoxSizeMode.Zoom,
            BackColor = Color.Black
        };
        panel.Controls.Add(previewBox, 0, 1);

        var infoLabel = new Label
        {
            Dock = DockStyle.Fill,
            AutoSize = true,
            MaximumSize = new Size(520, 0),
            Padding = new Padding(0, 6, 0, 0)
        };
        panel.Controls.Add(infoLabel, 0, 2);

        if (!IsImageFile(path))
        {
            previewBox.BackColor = SystemColors.ControlDark;
            infoLabel.Text = "非图片资源：当前显示文本预览、格式检查和风险提示；EEX/E5/E5S/WAV/MP3 的内部可视化仍在后续计划中。";
            return panel;
        }

        try
        {
            using var image = Image.FromFile(path);
            previewBox.Image = new Bitmap(image);
            infoLabel.Text = $"图片可读：{image.Width}x{image.Height}    文件：{path}";
            disposeOnClose.FormClosed += (_, _) => previewBox.Image?.Dispose();
        }
        catch (Exception ex)
        {
            previewBox.BackColor = SystemColors.ControlDark;
            infoLabel.Text = "图片预览失败：" + ex.Message + "\r\n文件：" + path;
        }

        return panel;
    }

    private static bool IsImageFile(string path)
    {
        var ext = Path.GetExtension(path);
        return ext.Equals(".jpg", StringComparison.OrdinalIgnoreCase) ||
               ext.Equals(".jpeg", StringComparison.OrdinalIgnoreCase) ||
               ext.Equals(".png", StringComparison.OrdinalIgnoreCase) ||
               ext.Equals(".bmp", StringComparison.OrdinalIgnoreCase);
    }

    private static string FormatSignedBytes(long value)
    {
        return value switch
        {
            > 0 => "+" + value.ToString("N0", CultureInfo.CurrentCulture) + " 字节",
            < 0 => value.ToString("N0", CultureInfo.CurrentCulture) + " 字节",
            _ => "0 字节"
        };
    }

    private static string ShortSha256(string sha256)
    {
        if (string.IsNullOrWhiteSpace(sha256)) return string.Empty;
        return sha256.Length <= 16 ? sha256 : sha256[..16] + "…";
    }

    private void ExportGameResourcesCsv()
    {
        if (_currentGameResources.Count == 0)
        {
            MessageBox.Show(this, "\u8bf7\u5148\u7d22\u5f15\u6e38\u620f\u8d44\u6e90\u3002", "\u63d0\u793a", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        using var dialog = new SaveFileDialog
        {
            Title = "\u5bfc\u51fa\u6e38\u620f\u8d44\u6e90\u7d22\u5f15",
            Filter = "CSV \u6587\u4ef6 (*.csv)|*.csv|\u6240\u6709\u6587\u4ef6 (*.*)|*.*",
            FileName = "\u6e38\u620f\u8d44\u6e90\u7d22\u5f15.csv"
        };
        if (dialog.ShowDialog(this) != DialogResult.OK) return;

        try
        {
            var table = new DataTable("GameResources");
            table.Columns.Add("Category");
            table.Columns.Add("Id");
            table.Columns.Add("Name");
            table.Columns.Add("Extension");
            table.Columns.Add("SizeBytes", typeof(long));
            table.Columns.Add("Magic");
            table.Columns.Add("FormatHint");
            table.Columns.Add("Annotation");
            table.Columns.Add("Width", typeof(int));
            table.Columns.Add("Height", typeof(int));
            table.Columns.Add("Path");
            foreach (var item in _currentGameResources)
            {
                table.Rows.Add(item.Category, item.Id, item.Name, item.Extension, item.SizeBytes, item.Magic, item.FormatHint, item.Annotation, item.Width, item.Height, item.Path);
            }

            CsvService.Export(table, dialog.FileName);
            Log($"\u5df2\u5bfc\u51fa\u6e38\u620f\u8d44\u6e90\u7d22\u5f15\uff1a{dialog.FileName}\uff0c\u9879\u6570 {_currentGameResources.Count}");
            SetStatus($"\u6e38\u620f\u8d44\u6e90\u7d22\u5f15\u5bfc\u51fa\u5b8c\u6210\uff1a{_currentGameResources.Count} \u9879");
        }
        catch (Exception ex)
        {
            Log("\u5bfc\u51fa\u6e38\u620f\u8d44\u6e90\u7d22\u5f15\u5931\u8d25\uff1a" + ex);
            MessageBox.Show(this, ex.Message, "\u5bfc\u51fa\u5931\u8d25", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }


    private void RunResourceDiagnostics()
    {
        if (_project == null)
        {
            MessageBox.Show(this, "\u8bf7\u5148\u52a0\u8f7d\u9879\u76ee\u3002", "\u63d0\u793a", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        try
        {
            Cursor = Cursors.WaitCursor;
            if (_currentGameResources.Count == 0)
            {
                _currentGameResources = _gameResourceIndexer.Index(_project);
                PopulateGameResourceCategoryFilter();
                BindGameResourceRows(_currentGameResources);
                UpdateGameResourceInfo(_currentGameResources.Count, "\u5168\u90e8", string.Empty);
                var maps = _currentGameResources
                    .Where(x => x.Category == "\u5730\u56fe\u56fe\u7247")
                    .OrderBy(x => x.Id)
                    .ThenBy(x => x.Name, StringComparer.CurrentCultureIgnoreCase)
                    .ToList();
                _mapImageList.DisplayMember = nameof(ResourceIndexItem.Name);
                _mapImageList.DataSource = new BindingList<ResourceIndexItem>(maps);
                Log($"\u8d44\u6e90\u8bca\u65ad\u524d\u5df2\u81ea\u52a8\u7d22\u5f15\u6e38\u620f\u8d44\u6e90\uff1a{_currentGameResources.Count} \u9879\u3002");
            }

            var diagnostics = _resourceDiagnosticService.Analyze(_currentGameResources).ToList();
            if (_tables.Count > 0)
            {
                try
                {
                    var imageAssignments = _currentImageAssignments ?? _imageAssignmentService.Load(_project, _tables);
                    diagnostics.AddRange(_resourceReferenceDiagnosticService.AnalyzeImageAssignments(_project, imageAssignments, _currentGameResources));
                }
                catch (Exception referenceEx)
                {
                    diagnostics.Add(new ResourceDiagnosticItem
                    {
                        Severity = "Info",
                        Category = "\u8868\u683c\u5f15\u7528",
                        Rule = "\u5f15\u7528\u8bca\u65ad\u8df3\u8fc7",
                        Id = string.Empty,
                        Name = "\u4eba\u7269 R/S \u5f62\u8c61",
                        Status = referenceEx.Message,
                        Detail = "\u672a\u80fd\u8bfb\u53d6\u4eba\u7269\u5f62\u8c61\u8054\u52a8\u8868\uff1a" + referenceEx.Message,
                        Suggestion = "\u8bf7\u5148\u786e\u8ba4 6.5 \u4eba\u7269/R/S \u5f62\u8c61\u8868\u53ef\u8bfb\uff1b\u8d44\u6e90\u6587\u4ef6\u81ea\u8eab\u8bca\u65ad\u4ecd\u5df2\u751f\u6210\u3002",
                        Path = _project.GameRoot
                    });
                    Log("\u8d44\u6e90\u5f15\u7528\u8bca\u65ad\u8df3\u8fc7\uff1a" + referenceEx);
                }

                try
                {
                    diagnostics.AddRange(_tableReferenceDiagnosticService.Analyze(_project, _tables));
                }
                catch (Exception tableReferenceEx)
                {
                    diagnostics.Add(new ResourceDiagnosticItem
                    {
                        Severity = "Info",
                        Category = "表格引用/数据表",
                        Rule = "跨表引用诊断跳过",
                        Id = "0",
                        Name = "人物/物品/兵种/商店/专属装备",
                        Status = tableReferenceEx.Message,
                        Detail = "源表：6.5-0 人物；行 ID：0；字段：职业；未能生成数据表跨表引用诊断：" + tableReferenceEx.Message,
                        Suggestion = "请确认 HexTable.xml 与核心表文件可读；其他资源文件自身诊断仍已生成。可先在数据表页查看字段中文注释和跨表解释。",
                        Path = _project.GameRoot
                    });
                    Log("数据表跨表引用诊断跳过：" + tableReferenceEx);
                }
            }

            try
            {
                var scenarioMapLinks = EnsureScenarioMapLinksForDiagnostics();
                diagnostics.AddRange(_resourceReferenceDiagnosticService.AnalyzeScenarioMapLinks(_project, scenarioMapLinks));
            }
            catch (Exception scenarioMapEx)
            {
                diagnostics.Add(new ResourceDiagnosticItem
                {
                    Severity = "Info",
                    Category = "关卡地图联动",
                    Rule = "联动诊断跳过",
                    Id = string.Empty,
                    Name = "R/S eex/Map/Hexzmap",
                    Status = scenarioMapEx.Message,
                    Detail = "未能生成关卡地图联动诊断：" + scenarioMapEx.Message,
                    Suggestion = "请确认 SV 目录、Map 图片和 Hexzmap.e5 可读取；其他资源文件自身诊断仍已生成。",
                    Path = _project.GameRoot
                });
                Log("关卡地图联动诊断跳过：" + scenarioMapEx);
            }

            _currentResourceDiagnostics = diagnostics
                .OrderByDescending(x => ResourceDiagnosticSeverityRank(x.Severity))
                .ThenBy(x => x.Category, StringComparer.CurrentCultureIgnoreCase)
                .ThenBy(x => x.Rule, StringComparer.CurrentCultureIgnoreCase)
                .ThenBy(x => x.Id, StringComparer.CurrentCultureIgnoreCase)
                .ThenBy(x => x.Name, StringComparer.CurrentCultureIgnoreCase)
                .ToList();
            PopulateResourceDiagnosticSeverityFilter();
            PopulateResourceDiagnosticCategoryFilter();
            BindResourceDiagnosticRows(_currentResourceDiagnostics);
            UpdateResourceDiagnosticInfo(_currentResourceDiagnostics.Count, "\u5168\u90e8", "\u5168\u90e8", string.Empty);
            var errors = _currentResourceDiagnostics.Count(x => x.Severity == "Error");
            var warnings = _currentResourceDiagnostics.Count(x => x.Severity == "Warn");
            var infos = _currentResourceDiagnostics.Count(x => x.Severity == "Info");
            Log($"\u8d44\u6e90\u8bca\u65ad\u5b8c\u6210\uff1a{_currentResourceDiagnostics.Count} \u9879\uff0cError={errors}\uff0cWarn={warnings}\uff0cInfo={infos}\u3002");
            SetStatus($"\u8d44\u6e90\u8bca\u65ad\u5b8c\u6210\uff1a{_currentResourceDiagnostics.Count} \u9879");
            RefreshWorkflowGuide(updateStatus: false);
        }
        catch (Exception ex)
        {
            _resourceDiagnosticInfoBox.Text = ex.ToString();
            Log("\u8d44\u6e90\u8bca\u65ad\u5931\u8d25\uff1a" + ex);
            MessageBox.Show(this, ex.Message, "\u8d44\u6e90\u8bca\u65ad\u5931\u8d25", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
        finally
        {
            Cursor = Cursors.Default;
        }
    }

    private IReadOnlyList<ScenarioMapLinkInfo> EnsureScenarioMapLinksForDiagnostics()
    {
        if (_project == null) return Array.Empty<ScenarioMapLinkInfo>();
        if (_currentScenarioMapLinks.Count > 0) return _currentScenarioMapLinks;

        if (_currentScenarioFiles.Count == 0)
        {
            var dictionary = _currentSceneStringDocument ?? TryReadSceneDictionaryForProbe();
            _currentScenarioFiles = _scenarioFileReader.ReadAllIndex(_project);
        }

        if (_currentGameResources.Count == 0)
        {
            _currentGameResources = _gameResourceIndexer.Index(_project);
        }

        if (_currentHexzmapProbe == null)
        {
            var terrainLookup = BuildTerrainNameLookupForCurrentProject();
            _currentHexzmapProbe = _hexzmapProbeReader.Read(_project, terrainLookup);
        }

        _currentScenarioMapLinks = _scenarioMapLinkService.BuildLinks(_currentScenarioFiles, _currentGameResources, _currentHexzmapProbe);
        return _currentScenarioMapLinks;
    }

    private void BindResourceDiagnosticRows(IEnumerable<ResourceDiagnosticItem> rows)
    {
        _resourceDiagnosticGrid.DataSource = new BindingList<ResourceDiagnosticItem>(rows.ToList());
        ConfigureResourceDiagnosticGrid();
        HighlightRowsWithCreatorNotes<ResourceDiagnosticItem>(
            _resourceDiagnosticGrid,
            item => ("资源诊断", BuildResourceDiagnosticCreatorNoteTargetKey(item)));
    }

    private void ConfigureResourceDiagnosticGrid()
    {
        if (_resourceDiagnosticGrid.Columns.Count == 0) return;

        SetResourceDiagnosticColumn(nameof(ResourceDiagnosticItem.Severity), "\u7ea7\u522b", 70);
        SetResourceDiagnosticColumn(nameof(ResourceDiagnosticItem.Category), "\u5206\u7c7b", 100);
        SetResourceDiagnosticColumn(nameof(ResourceDiagnosticItem.Rule), "\u89c4\u5219", 130);
        SetResourceDiagnosticColumn(nameof(ResourceDiagnosticItem.Id), "\u7f16\u53f7/\u8303\u56f4", 90);
        SetResourceDiagnosticColumn(nameof(ResourceDiagnosticItem.Name), "\u6587\u4ef6/\u5bf9\u8c61", 180);
        SetResourceDiagnosticColumn(nameof(ResourceDiagnosticItem.Status), "\u72b6\u6001", 160);
        SetResourceDiagnosticColumn(nameof(ResourceDiagnosticItem.Detail), "\u8bc1\u636e\u8be6\u60c5", 360);
        SetResourceDiagnosticColumn(nameof(ResourceDiagnosticItem.Suggestion), "\u521b\u4f5c\u5efa\u8bae", 360);
        SetResourceDiagnosticColumn(nameof(ResourceDiagnosticItem.Path), "\u8def\u5f84", 260);

        foreach (DataGridViewRow row in _resourceDiagnosticGrid.Rows)
        {
            if (row.DataBoundItem is not ResourceDiagnosticItem item) continue;
            row.DefaultCellStyle.BackColor = item.Severity switch
            {
                "Error" => Color.MistyRose,
                "Warn" => Color.LemonChiffon,
                "Info" => Color.AliceBlue,
                _ => row.DefaultCellStyle.BackColor
            };
        }
    }

    private void SetResourceDiagnosticColumn(string columnName, string headerText, int width)
    {
        if (!_resourceDiagnosticGrid.Columns.Contains(columnName)) return;
        var column = _resourceDiagnosticGrid.Columns[columnName];
        column.HeaderText = headerText;
        column.Width = width;
        column.MinimumWidth = Math.Min(width, 80);
        if (columnName is nameof(ResourceDiagnosticItem.Detail) or nameof(ResourceDiagnosticItem.Suggestion) or nameof(ResourceDiagnosticItem.Path))
        {
            column.AutoSizeMode = DataGridViewAutoSizeColumnMode.None;
        }
    }

    private void PopulateResourceDiagnosticSeverityFilter()
    {
        var previous = Convert.ToString(_resourceDiagnosticSeverityFilterCombo.SelectedItem, CultureInfo.InvariantCulture);
        _resourceDiagnosticSeverityFilterCombo.Items.Clear();
        _resourceDiagnosticSeverityFilterCombo.Items.Add("\u5168\u90e8");
        foreach (var severity in _currentResourceDiagnostics
                     .Select(x => x.Severity)
                     .Where(x => !string.IsNullOrWhiteSpace(x))
                     .Distinct(StringComparer.OrdinalIgnoreCase)
                     .OrderByDescending(ResourceDiagnosticSeverityRank)
                     .ThenBy(x => x, StringComparer.CurrentCultureIgnoreCase))
        {
            _resourceDiagnosticSeverityFilterCombo.Items.Add(severity);
        }

        var selectedIndex = 0;
        if (!string.IsNullOrWhiteSpace(previous))
        {
            for (var i = 0; i < _resourceDiagnosticSeverityFilterCombo.Items.Count; i++)
            {
                if (string.Equals(Convert.ToString(_resourceDiagnosticSeverityFilterCombo.Items[i], CultureInfo.InvariantCulture), previous, StringComparison.OrdinalIgnoreCase))
                {
                    selectedIndex = i;
                    break;
                }
            }
        }

        _resourceDiagnosticSeverityFilterCombo.SelectedIndex = selectedIndex;
    }

    private void PopulateResourceDiagnosticCategoryFilter()
    {
        var previous = Convert.ToString(_resourceDiagnosticCategoryFilterCombo.SelectedItem, CultureInfo.InvariantCulture);
        _resourceDiagnosticCategoryFilterCombo.Items.Clear();
        _resourceDiagnosticCategoryFilterCombo.Items.Add("\u5168\u90e8");
        foreach (var category in _currentResourceDiagnostics
                     .Select(x => x.Category)
                     .Where(x => !string.IsNullOrWhiteSpace(x))
                     .Distinct(StringComparer.OrdinalIgnoreCase)
                     .OrderBy(x => x, StringComparer.CurrentCultureIgnoreCase))
        {
            _resourceDiagnosticCategoryFilterCombo.Items.Add(category);
        }

        var selectedIndex = 0;
        if (!string.IsNullOrWhiteSpace(previous))
        {
            for (var i = 0; i < _resourceDiagnosticCategoryFilterCombo.Items.Count; i++)
            {
                if (string.Equals(Convert.ToString(_resourceDiagnosticCategoryFilterCombo.Items[i], CultureInfo.InvariantCulture), previous, StringComparison.OrdinalIgnoreCase))
                {
                    selectedIndex = i;
                    break;
                }
            }
        }

        _resourceDiagnosticCategoryFilterCombo.SelectedIndex = selectedIndex;
    }

    private void ApplyResourceDiagnosticFilter()
    {
        if (_currentResourceDiagnostics.Count == 0)
        {
            return;
        }

        var severity = Convert.ToString(_resourceDiagnosticSeverityFilterCombo.SelectedItem, CultureInfo.InvariantCulture) ?? "\u5168\u90e8";
        var category = Convert.ToString(_resourceDiagnosticCategoryFilterCombo.SelectedItem, CultureInfo.InvariantCulture) ?? "\u5168\u90e8";
        var keyword = _resourceDiagnosticSearchBox.Text.Trim();
        var filtered = _currentResourceDiagnostics.Where(item =>
                (severity == "\u5168\u90e8" || string.Equals(item.Severity, severity, StringComparison.OrdinalIgnoreCase)) &&
                (category == "\u5168\u90e8" || string.Equals(item.Category, category, StringComparison.OrdinalIgnoreCase)) &&
                (string.IsNullOrWhiteSpace(keyword) || ResourceDiagnosticMatchesKeyword(item, keyword)))
            .ToList();
        BindResourceDiagnosticRows(filtered);
        UpdateResourceDiagnosticInfo(filtered.Count, severity, category, keyword);
        SetStatus($"\u8d44\u6e90\u8bca\u65ad\u7b5b\u9009\uff1a{filtered.Count}/{_currentResourceDiagnostics.Count}");
    }

    private void ClearResourceDiagnosticFilter()
    {
        _resourceDiagnosticSearchBox.Clear();
        if (_resourceDiagnosticSeverityFilterCombo.Items.Count > 0) _resourceDiagnosticSeverityFilterCombo.SelectedIndex = 0;
        if (_resourceDiagnosticCategoryFilterCombo.Items.Count > 0) _resourceDiagnosticCategoryFilterCombo.SelectedIndex = 0;
        BindResourceDiagnosticRows(_currentResourceDiagnostics);
        UpdateResourceDiagnosticInfo(_currentResourceDiagnostics.Count, "\u5168\u90e8", "\u5168\u90e8", string.Empty);
        SetStatus("\u5df2\u663e\u793a\u5168\u90e8\u8d44\u6e90\u8bca\u65ad\u9879");
    }

    private static bool ResourceDiagnosticMatchesKeyword(ResourceDiagnosticItem item, string keyword)
    {
        return ContainsKeyword(item.Severity, keyword) ||
               ContainsKeyword(item.Category, keyword) ||
               ContainsKeyword(item.Rule, keyword) ||
               ContainsKeyword(item.Id, keyword) ||
               ContainsKeyword(item.Name, keyword) ||
               ContainsKeyword(item.Status, keyword) ||
               ContainsKeyword(item.Detail, keyword) ||
               ContainsKeyword(item.Suggestion, keyword) ||
               ContainsKeyword(item.Path, keyword);
    }

    private void UpdateResourceDiagnosticInfo(int visibleCount, string severity, string category, string keyword)
    {
        var errors = _currentResourceDiagnostics.Count(x => x.Severity == "Error");
        var warnings = _currentResourceDiagnostics.Count(x => x.Severity == "Warn");
        var infos = _currentResourceDiagnostics.Count(x => x.Severity == "Info");
        var categorySummary = string.Join("\uff0c", _currentResourceDiagnostics
            .GroupBy(x => x.Category)
            .OrderByDescending(x => x.Count())
            .ThenBy(x => x.Key, StringComparer.CurrentCultureIgnoreCase)
            .Take(10)
            .Select(x => $"{x.Key}:{x.Count()}"));
        var filterText = severity == "\u5168\u90e8" && category == "\u5168\u90e8" && string.IsNullOrWhiteSpace(keyword)
            ? "\u672a\u7b5b\u9009"
            : $"\u7ea7\u522b={severity}\uff0c\u5206\u7c7b={category}\uff0c\u5173\u952e\u5b57={keyword}";

        _resourceDiagnosticInfoBox.Text =
            $"\u8d44\u6e90\u8bca\u65ad\u57fa\u4e8e\u5f53\u524d\u6e38\u620f\u8d44\u6e90\u7d22\u5f15\uff1a\u8d44\u6e90 {_currentGameResources.Count} \u9879\uff0c\u8bca\u65ad {_currentResourceDiagnostics.Count} \u9879\uff0c\u5f53\u524d\u663e\u793a {visibleCount} \u9879\u3002\r\n" +
            $"\u7ea7\u522b\u7edf\u8ba1\uff1aError={errors}\uff0cWarn={warnings}\uff0cInfo={infos}\uff1b\u5206\u7c7b\u6458\u8981\uff1a{categorySummary}\r\n" +
            $"\u7b5b\u9009\uff1a{filterText}\r\n" +
            "\u8bf4\u660e\uff1aError \u901a\u5e38\u9700\u8981\u4fee\u590d\uff1bWarn \u5efa\u8bae\u53d1\u5e03\u524d\u786e\u8ba4\uff1bInfo \u591a\u4e3a\u89c4\u6a21\u6982\u89c8\u3001\u7f3a\u53f7\u63d0\u793a\u6216\u53ef\u9009\u6574\u7406\u5efa\u8bae\u3002\u9009\u4e2d\u4efb\u610f\u884c\u53ef\u67e5\u770b\u8bc1\u636e\u8def\u5f84\u548c\u5904\u7406\u5efa\u8bae\uff0c\u5e76\u53ef\u7528\u201c\u8df3\u5230\u4eba\u7269R/S/\u8df3\u5230\u6570\u636e\u8868/\u8df3\u5230\u8054\u52a8\u9875/\u8df3\u5230SV/\u8df3\u5230\u5730\u5f62/\u8df3\u5230\u5730\u56fe\u201d\u76f4\u63a5\u5b9a\u4f4d\u5173\u8054\u5bf9\u8c61\u3002";
    }

    private void ShowSelectedResourceDiagnostic()
    {
        var item = GetSelectedResourceDiagnosticItem();
        if (item == null) return;

        var navigationTarget = ResolveResourceDiagnosticNavigationTarget(item, ensureScenarioLinks: false);
        UpdateResourceDiagnosticNavigationButtons(navigationTarget);
        _resourceDiagnosticInfoBox.Text =
            $"\u9009\u4e2d\u8bca\u65ad\uff1a[{item.Severity}] {item.Category}/{item.Rule}    \u7f16\u53f7={item.Id}\r\n" +
            $"\u5bf9\u8c61\uff1a{item.Name}    \u72b6\u6001\uff1a{item.Status}\r\n" +
            $"\u8bc1\u636e\uff1a{item.Detail}\r\n" +
            $"\u5efa\u8bae\uff1a{item.Suggestion}\r\n" +
            $"\u8def\u5f84\uff1a{item.Path}\r\n" +
            BuildResourceDiagnosticNavigationText(navigationTarget) +
            BuildRelatedCreatorNotesText("资源诊断", BuildResourceDiagnosticCreatorNoteTargetKey(item));
        SetLastCreatorNoteContext(
            "资源诊断",
            BuildResourceDiagnosticCreatorNoteTargetKey(item),
            $"资源诊断：{item.Category}/{item.Rule}/{item.Name}",
            "从资源诊断页抓取；用于记录处理结论、风险确认和发布前复查。",
            $"诊断级别：{item.Severity}\r\n状态：{item.Status}\r\n证据：{item.Detail}\r\n建议：{item.Suggestion}\r\n处理结论：\r\n实机验证：");
    }

    private static string BuildResourceDiagnosticCreatorNoteTargetKey(ResourceDiagnosticItem item)
        => $"资源诊断#分类={item.Category}#规则={item.Rule}#编号={item.Id}#对象={item.Name}";

    private ResourceDiagnosticNavigationTarget ResolveResourceDiagnosticNavigationTarget(ResourceDiagnosticItem item, bool ensureScenarioLinks)
    {
        if (_project != null && ensureScenarioLinks && _currentGameResources.Count == 0)
        {
            _currentGameResources = _gameResourceIndexer.Index(_project);
            PopulateGameResourceCategoryFilter();
        }

        var links = _currentScenarioMapLinks;
        if (_project != null && ensureScenarioLinks && links.Count == 0)
        {
            links = EnsureScenarioMapLinksForDiagnostics();
        }

        return _resourceDiagnosticNavigationService.Resolve(item, links, _currentGameResources);
    }

    private ResourceDiagnosticNavigationTarget? ResolveSelectedResourceDiagnosticNavigationTarget(bool ensureScenarioLinks)
    {
        var item = GetSelectedResourceDiagnosticItem();
        if (item == null)
        {
            MessageBox.Show(this, "请先在资源诊断页选择一条诊断。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return null;
        }

        var target = ResolveResourceDiagnosticNavigationTarget(item, ensureScenarioLinks);
        UpdateResourceDiagnosticNavigationButtons(target);
        return target;
    }

    private void UpdateResourceDiagnosticNavigationButtons(ResourceDiagnosticNavigationTarget target)
    {
        _jumpDiagnosticScenarioMapButton.Enabled = target.CanOpenScenarioMapLink;
        _jumpDiagnosticScenarioButton.Enabled = target.CanJumpScenario;
        _jumpDiagnosticHexzmapButton.Enabled = target.CanJumpHexzmap;
        _jumpDiagnosticMapViewerButton.Enabled = target.CanJumpMapViewer;
        _jumpDiagnosticImageAssignmentButton.Enabled = target.CanJumpImageAssignment;
        _jumpDiagnosticTableCellButton.Enabled = target.CanJumpDataTable;
    }

    private static string BuildResourceDiagnosticNavigationText(ResourceDiagnosticNavigationTarget target)
    {
        if (!target.IsRecognized)
        {
            return "联动定位：暂未识别到可直接跳转对象；可先查看证据路径或用“定位到资源索引”。";
        }

        var actions = new List<string>();
        if (target.CanJumpImageAssignment) actions.Add("跳到人物R/S");
        if (target.CanJumpDataTable) actions.Add("跳到数据表");
        if (target.CanOpenScenarioMapLink) actions.Add("跳到联动页");
        if (target.CanJumpScenario) actions.Add("跳到RS");
        if (target.CanJumpHexzmap) actions.Add("跳到地形");
        if (target.CanJumpMapViewer) actions.Add("跳到地图");
        return $"联动定位：{target.Summary}；可用按钮：{(actions.Count == 0 ? "暂无直接按钮" : string.Join("、", actions))}。";
    }

    private void JumpSelectedDiagnosticImageAssignment()
    {
        var target = ResolveSelectedResourceDiagnosticNavigationTarget(ensureScenarioLinks: false);
        if (target == null) return;
        if (!target.CanJumpImageAssignment)
        {
            MessageBox.Show(this, "该诊断没有可定位的人物 R/S 形象行。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        SelectTabPageByText("形象设定");
        if (_currentImageAssignments == null || _currentImageAssignments.Rows.Count == 0)
        {
            LoadImageAssignments();
        }

        if (_currentImageAssignments == null || _currentImageAssignments.Rows.Count == 0)
        {
            return;
        }

        if (!string.IsNullOrWhiteSpace(_currentImageAssignments.DefaultView.RowFilter) ||
            !string.IsNullOrWhiteSpace(_imageAssignmentSearchBox.Text) ||
            _imageAssignmentMissingOnlyCheckBox.Checked)
        {
            ClearImageAssignmentFilter();
        }

        var preferredColumn = target.ImageAssignmentPrefix == "S" ? "S形象编号" : "R形象编号";
        var found = false;
        if (target.ImageAssignmentRowId.HasValue)
        {
            found = SelectImageAssignmentRow(row =>
                int.TryParse(Convert.ToString(row["ID"], CultureInfo.InvariantCulture), NumberStyles.Integer, CultureInfo.InvariantCulture, out var rowId) &&
                rowId == target.ImageAssignmentRowId.Value,
                preferredColumn);
        }

        if (!found && target.ImageResourceId.HasValue)
        {
            found = SelectImageAssignmentRow(row =>
                TryGetImageResourceId(row, target.ImageAssignmentPrefix, out var resourceId) &&
                resourceId == target.ImageResourceId.Value,
                preferredColumn);
        }

        if (found)
        {
            ShowSelectedImageAssignmentDetail();
            SetStatus($"已从资源诊断跳转到人物 {target.ImageAssignmentPrefix} 形象：行={target.ImageAssignmentRowId?.ToString(CultureInfo.InvariantCulture) ?? "按资源"}，资源={target.ImageResourceId?.ToString("00", CultureInfo.InvariantCulture) ?? "未指定"}");
            return;
        }

        MessageBox.Show(this,
            target.ImageResourceId.HasValue
                ? $"已打开人物 R/S 形象页，但没有找到引用 {target.ImageAssignmentPrefix}_{target.ImageResourceId.Value:00} 的人物行；该资源可能未被人物表引用。"
                : "已打开人物 R/S 形象页，但没有找到对应人物行。",
            "未找到对应行",
            MessageBoxButtons.OK,
            MessageBoxIcon.Information);
    }

    private void JumpSelectedDiagnosticTableCell()
