    {
        _eexArchiveGrid.DataSource = new BindingList<EexArchiveInfo>(rows.ToList());
        ConfigureEexArchiveGrid();
        HighlightRowsWithCreatorNotes<EexArchiveInfo>(
            _eexArchiveGrid,
            item => ("EEX资源", $"{item.Category}/{item.FileName}"));
